    /// Best-effort named-struct Mako name for an expression (Point, not C type).
    fn struct_name_from_expr(&self, e: &Expr) -> Option<String> {
        match e {
            Expr::StructLit { name, .. } | Expr::StructLitPos { name, .. } => {
                if self.structs.contains_key(name) {
                    Some(name.clone())
                } else {
                    // Pack-qualified / already C-mangled — accept if registered by c_name.
                    self.structs
                        .iter()
                        .find(|(_, s)| s.c_name == *name)
                        .map(|(n, _)| n.clone())
                }
            }
            Expr::Ident(n) => {
                let cty = self.locals.get(n)?;
                if cty == "int64_t"
                    || cty == "bool"
                    || cty == "double"
                    || cty == "MakoString"
                    || cty.ends_with('*')
                    || cty.starts_with("Mako")
                {
                    return None;
                }
                // Locals store C names for structs; map back to Mako name when needed.
                if self.structs.contains_key(cty) {
                    return Some(cty.clone());
                }
                self.structs
                    .iter()
                    .find(|(_, s)| &s.c_name == cty)
                    .map(|(n, _)| n.clone())
            }
            _ => None,
        }
    }

    /// Bind Option Some payload into `bindings[0]` according to kind.
    fn emit_option_some_bind(&mut self, scrut: &str, bindings: &[String], kind: &str) {
        if bindings.len() != 1 {
            return;
        }
        let b = mangle(&bindings[0]);
        if kind == "option" {
            // Nested Option: unbox heap Option and consume one link of the kind chain.
            let p = self.fresh("opnest");
            self.locals.insert(bindings[0].clone(), "MakoOptionInt".into());
            self.line(&format!(
                "MakoOptionInt *{p} = (MakoOptionInt*)mako_option_some_ptr({scrut});"
            ));
            self.line(&format!("MakoOptionInt {b};"));
            self.line(&format!(
                "if ({p}) {{ {b} = *{p}; free({p}); }} else {{ memset(&{b}, 0, sizeof({b})); }}"
            ));
            if let Some(chain) = self.deep_nest_chains.get(scrut).cloned() {
                self.apply_deep_nest_chain(&bindings[0], "option", &chain);
            } else {
                let chain = self
                    .option_chains
                    .get(scrut)
                    .cloned()
                    .unwrap_or_default();
                if let Some((next, rest)) = chain.split_first() {
                    self.option_some_kinds
                        .insert(bindings[0].clone(), next.clone());
                    if next == "option" && !rest.is_empty() {
                        self.option_chains
                            .insert(bindings[0].clone(), rest.to_vec());
                    } else if next == "option" {
                        self.option_chains
                            .insert(bindings[0].clone(), Vec::new());
                    }
                    if next == "result" {
                        if let Some(rik) = self.option_result_inners.get(scrut).cloned() {
                            self.result_ok_kinds.insert(bindings[0].clone(), rik);
                        }
                    }
                    // Propagate struct / struct-chan names for deeper match arms.
                    if next == "struct" || next == "chan_struct" || next == "slice_struct" {
                        if let Some(sn) = self.option_some_structs.get(scrut).cloned() {
                            self.option_some_structs
                                .insert(bindings[0].clone(), sn);
                        }
                    }
                } else {
                    self.option_some_kinds
                        .insert(bindings[0].clone(), "int".into());
                }
            }
            return;
        }
        if kind == "result" {
            // Option[Result[T,E]]: unbox nested Result
            let p = self.fresh("opres");
            self.locals.insert(bindings[0].clone(), "MakoResultInt".into());
            self.line(&format!(
                "MakoResultInt *{p} = (MakoResultInt*)mako_option_some_ptr({scrut});"
            ));
            self.line(&format!("MakoResultInt {b};"));
            self.line(&format!(
                "if ({p}) {{ {b} = *{p}; free({p}); }} else {{ memset(&{b}, 0, sizeof({b})); }}"
            ));
            if let Some(chain) = self.deep_nest_chains.get(scrut).cloned() {
                self.apply_deep_nest_chain(&bindings[0], "result", &chain);
            } else if let Some(ik) = self.option_result_inners.get(scrut).cloned() {
                // Option[Result[Option[T]]]: after Ok, Option needs leaf Some-kind
                if ik == "option" {
                    if let Some(leaf) = self.option_result_option_leafs.get(scrut).cloned() {
                        self.result_option_inners
                            .insert(bindings[0].clone(), leaf);
                    }
                    // Propagate deeper Option chains if any
                    if let Some(ch) = self.result_option_chains.get(scrut).cloned() {
                        self.result_option_chains
                            .insert(bindings[0].clone(), ch);
                    }
                }
                self.result_ok_kinds.insert(bindings[0].clone(), ik);
            }
            // Propagate struct / chan_struct names onto the nested Result binding
            if let Some(sn) = self
                .result_ok_structs
                .get(scrut)
                .cloned()
                .or_else(|| self.option_some_structs.get(scrut).cloned())
            {
                self.result_ok_structs
                    .insert(bindings[0].clone(), sn.clone());
                self.option_some_structs
                    .insert(bindings[0].clone(), sn);
            }
            // Channel float / nested Result metadata
            if let Some(rik) = self.result_result_inners.get(scrut).cloned() {
                self.result_result_inners
                    .insert(bindings[0].clone(), rik);
            }
            return;
        }
        if kind == "string" {
            self.locals.insert(bindings[0].clone(), "MakoString".into());
            self.line(&format!("MakoString {b} = {scrut}.ok_s;"));
        } else if kind == "float" {
            self.locals.insert(bindings[0].clone(), "double".into());
            self.line(&format!("double {b} = {scrut}.ok_f;"));
        } else if kind == "struct" {
            let sn = self
                .option_some_structs
                .get(scrut)
                .cloned()
                .unwrap_or_else(|| "int64_t".into());
            let cname = self
                .structs
                .get(&sn)
                .map(|s| s.c_name.clone())
                .unwrap_or(sn);
            let p = self.fresh("opp");
            self.locals.insert(bindings[0].clone(), cname.clone());
            self.line(&format!(
                "{cname} *{p} = ({cname}*)mako_option_some_ptr({scrut});"
            ));
            self.line(&format!("{cname} {b};"));
            self.line(&format!(
                "if ({p}) {{ {b} = *{p}; free({p}); }} else {{ memset(&{b}, 0, sizeof({b})); }}"
            ));
        } else if kind == "slice" {
            let p = self.fresh("ops");
            self.locals.insert(bindings[0].clone(), "MakoIntArray".into());
            self.line(&format!(
                "MakoIntArray *{p} = (MakoIntArray*)mako_option_some_ptr({scrut});"
            ));
            self.line(&format!("MakoIntArray {b};"));
            self.line(&format!(
                "if ({p}) {{ {b} = *{p}; free({p}); }} else {{ {b}.data = NULL; {b}.len = 0; {b}.cap = 0; }}"
            ));
        } else if kind == "slice_str" {
            let p = self.fresh("ops");
            self.locals.insert(bindings[0].clone(), "MakoStrArray".into());
            self.line(&format!(
                "MakoStrArray *{p} = (MakoStrArray*)mako_option_some_ptr({scrut});"
            ));
            self.line(&format!("MakoStrArray {b};"));
            self.line(&format!(
                "if ({p}) {{ {b} = *{p}; free({p}); }} else {{ {b}.data = NULL; {b}.len = 0; {b}.cap = 0; }}"
            ));
        } else if kind == "slice_float" {
            let p = self.fresh("ops");
            self.locals.insert(bindings[0].clone(), "MakoFloatArray".into());
            self.line(&format!(
                "MakoFloatArray *{p} = (MakoFloatArray*)mako_option_some_ptr({scrut});"
            ));
            self.line(&format!("MakoFloatArray {b};"));
            self.line(&format!(
                "if ({p}) {{ {b} = *{p}; free({p}); }} else {{ {b}.data = NULL; {b}.len = 0; {b}.cap = 0; }}"
            ));
        } else if kind == "slice_struct" {
            let sn = self
                .option_some_structs
                .get(scrut)
                .cloned()
                .unwrap_or_else(|| "int64_t".into());
            let cname = self
                .structs
                .get(&sn)
                .map(|s| s.c_name.clone())
                .unwrap_or(sn);
            let arr = format!("MakoArr_{cname}");
            let p = self.fresh("ops");
            self.locals.insert(bindings[0].clone(), arr.clone());
            self.line(&format!(
                "{arr} *{p} = ({arr}*)mako_option_some_ptr({scrut});"
            ));
            self.line(&format!("{arr} {b};"));
            self.line(&format!(
                "if ({p}) {{ {b} = *{p}; free({p}); }} else {{ {b}.data = NULL; {b}.len = 0; {b}.cap = 0; }}"
            ));
        } else if kind == "map"
            || kind == "map_si"
            || kind == "map_ii"
            || kind == "map_ss"
            || kind == "map_if"
            || kind == "map_sf"
            || kind == "map_fi"
            || kind == "map_fs"
            || kind == "map_ff"
            || kind == "map_ib"
            || kind == "map_sb"
            || kind == "map_fb"
            || kind == "map_bi"
            || kind == "map_bs"
            || kind == "map_bf"
            || kind == "map_bb"
            || kind == "map_ptr"
            || kind.starts_with("map_")
        {
            let cty = self
                .option_map_ctys
                .get(scrut)
                .cloned()
                .or_else(|| Self::map_kind_default_c_ty(kind).map(|s| s.to_string()))
                .unwrap_or_else(|| "MakoMapSI*".into());
            self.locals.insert(bindings[0].clone(), cty.clone());
            self.option_map_ctys
                .insert(bindings[0].clone(), cty.clone());
            self.line(&format!(
                "{cty} {b} = ({cty})mako_option_some_ptr({scrut});"
            ));
        } else if kind.starts_with("chan_") {
            // Option[chan[T]]: pointer in value slot (not heap-boxed header).
            let cty = match kind {
                "chan_string" => "MakoChanStr*".to_string(),
                "chan_struct" => "MakoChanPtr*".to_string(),
                _ => "MakoChan*".to_string(), // int / bool / float
            };
            self.locals.insert(bindings[0].clone(), cty.clone());
            self.line(&format!(
                "{cty} {b} = ({cty})mako_option_some_ptr({scrut});"
            ));
            // Float / struct-channel metadata for .send / .recv.
            if kind == "chan_float" {
                self.chan_float.insert(bindings[0].clone());
            } else if kind == "chan_struct" {
                if let Some(sn) = self.option_some_structs.get(scrut).cloned() {
                    self.chan_ptr_elems.insert(bindings[0].clone(), sn);
                }
            }
        } else {
            self.locals.insert(bindings[0].clone(), "int64_t".into());
            self.line(&format!("int64_t {b} = {scrut}.value;"));
        }
    }

    fn map_kind_default_c_ty(kind: &str) -> Option<&'static str> {
        Some(match kind {
            "map" | "map_si" => "MakoMapSI*",
            "map_ii" => "MakoMapII*",
            "map_ss" => "MakoMapSS*",
            "map_if" => "MakoMapIF*",
            "map_sf" => "MakoMapSF*",
            "map_fi" => "MakoMapFI*",
            "map_fs" => "MakoMapFS*",
            "map_ff" => "MakoMapFF*",
            "map_ib" => "MakoMapIB*",
            "map_sb" => "MakoMapSB*",
            "map_fb" => "MakoMapFB*",
            "map_bi" => "MakoMapBI*",
            "map_bs" => "MakoMapBS*",
            "map_bf" => "MakoMapBF*",
            "map_bb" => "MakoMapBB*",
            _ => return None,
        })
    }

    /// After map get of Option/Result bag, record Some/Ok kind for match arms.
    /// Record float / struct-channel metadata when loading a `chan_*` map value.
    fn register_chan_payload_on_temp(&mut self, temp: &str, tag: &str) {
        if tag == "chan_float" {
            self.chan_float.insert(temp.to_string());
        } else if let Some(rest) = tag.strip_prefix("chan_") {
            if rest != "int" && rest != "string" && rest != "bool" && rest != "float" {
                // Named struct element type for MakoChanPtr*
                self.chan_ptr_elems
                    .insert(temp.to_string(), rest.to_string());
            }
        }
    }

    fn register_bag_payload_on_temp(&mut self, temp: &str, tag: &str) {
        if let Some(rest) = tag.strip_prefix("opt_") {
            let kind = match rest {
                "int" | "bool" => "int".into(),
                "string" => "string".into(),
                "float" => "float".into(),
                "arr_int" | "arr_bool" | "arr_byte" => "slice".into(),
                "arr_string" => "slice_str".into(),
                "arr_float" => "slice_float".into(),
                other if other.starts_with("arr_") => {
                    let name = &other["arr_".len()..];
                    self.option_some_structs
                        .insert(temp.to_string(), name.to_string());
                    "slice_struct".into()
                }
                other if other.starts_with("map_") => {
                    let cty = map_map_val_c_ty(other);
                    self.option_map_ctys
                        .insert(temp.to_string(), cty);
                    other.to_string()
                }
                other if other.starts_with("opt_") => {
                    // Nested Option: opt_opt_int / opt_opt_chan_int / opt_opt_opt_int as payload.
                    // Outer kind is "option"; chain lists remaining Some-kinds after each unbox.
                    let chain = bag_opt_tag_to_chain(other);
                    if !chain.is_empty() {
                        self.option_chains.insert(temp.to_string(), chain);
                    }
                    // Struct leaf after nest: opt_opt_Point → last is Point
                    if let Some(leaf) = other.rsplit('_').next() {
                        if leaf != "int"
                            && leaf != "string"
                            && leaf != "float"
                            && leaf != "bool"
                            && !other.contains("chan_")
                        {
                            self.option_some_structs
                                .insert(temp.to_string(), leaf.to_string());
                        }
                    }
                    if other.contains("chan_") && !other.ends_with("chan_int")
                        && !other.ends_with("chan_string")
                        && !other.ends_with("chan_float")
                        && !other.ends_with("chan_bool")
                    {
                        // opt_opt_chan_Point → Point
                        if let Some(idx) = other.rfind("chan_") {
                            let sn = &other[idx + 5..];
                            if !sn.is_empty() {
                                self.option_some_structs
                                    .insert(temp.to_string(), sn.to_string());
                            }
                        }
                    }
                    "option".into()
                }
                other if other.starts_with("res_") => {
                    // Option[Result[…]]: opt_res_int / opt_res_chan_int / opt_res_opt_int
                    self.register_nested_result_payload(temp, other);
                    "result".into()
                }
                other if other.starts_with("chan_") => {
                    // opt_chan_int / opt_chan_Point → match kind chan_int / chan_struct
                    if other == "chan_float" {
                        "chan_float".into()
                    } else if other == "chan_string" {
                        "chan_string".into()
                    } else if other == "chan_bool" || other == "chan_int" {
                        other.to_string()
                    } else {
                        // chan_Point → chan_struct + struct name
                        let sn = &other["chan_".len()..];
                        self.option_some_structs
                            .insert(temp.to_string(), sn.to_string());
                        "chan_struct".into()
                    }
                }
                other => {
                    self.option_some_structs
                        .insert(temp.to_string(), other.to_string());
                    "struct".into()
                }
            };
            self.option_some_kinds.insert(temp.to_string(), kind);
            self.locals
                .insert(temp.to_string(), "MakoOptionInt".into());
        } else if let Some(rest) = tag.strip_prefix("res_") {
            let kind = match rest {
                "int" | "bool" => "int".into(),
                "string" => "string".into(),
                "float" => "float".into(),
                "arr_int" | "arr_bool" | "arr_byte" => "slice".into(),
                "arr_string" => "slice_str".into(),
                "arr_float" => "slice_float".into(),
                other if other.starts_with("arr_") => {
                    let name = &other["arr_".len()..];
                    self.result_ok_structs
                        .insert(temp.to_string(), name.to_string());
                    "slice_struct".into()
                }
                other if other.starts_with("map_") => {
                    let cty = map_map_val_c_ty(other);
                    self.result_ok_map_ctys
                        .insert(temp.to_string(), cty);
                    other.to_string()
                }
                other if other.starts_with("opt_") => {
                    // Result[Option[…],E]: Ok kind is nested option
                    // first chain element = immediate Some-kind; rest = deeper nest.
                    let chain = bag_opt_tag_to_chain(other);
                    if let Some((first, rest)) = chain.split_first() {
                        self.result_option_inners
                            .insert(temp.to_string(), first.clone());
                        if !rest.is_empty() {
                            self.result_option_chains
                                .insert(temp.to_string(), rest.to_vec());
                        }
                    }
                    // Struct / chan_struct leaf names for nested match
                    if other.contains("chan_")
                        && !other.ends_with("chan_int")
                        && !other.ends_with("chan_string")
                        && !other.ends_with("chan_float")
                        && !other.ends_with("chan_bool")
                    {
                        if let Some(idx) = other.rfind("chan_") {
                            let sn = &other[idx + 5..];
                            if !sn.is_empty() {
                                self.option_some_structs
                                    .insert(temp.to_string(), sn.to_string());
                            }
                        }
                    }
                    "option".into()
                }
                other if other.starts_with("res_") => {
                    // Result[Result[…]]: res_res_int / res_res_chan_int
                    self.register_nested_result_payload(temp, other);
                    "result".into()
                }
                other if other.starts_with("chan_") => {
                    if other == "chan_float" {
                        "chan_float".into()
                    } else if other == "chan_string" {
                        "chan_string".into()
                    } else if other == "chan_bool" || other == "chan_int" {
                        other.to_string()
                    } else {
                        let sn = &other["chan_".len()..];
                        self.result_ok_structs
                            .insert(temp.to_string(), sn.to_string());
                        "chan_struct".into()
                    }
                }
                other => {
                    self.result_ok_structs
                        .insert(temp.to_string(), other.to_string());
                    "struct".into()
                }
            };
            self.result_ok_kinds.insert(temp.to_string(), kind);
            self.locals
                .insert(temp.to_string(), "MakoResultInt".into());
        }
    }

    /// C type of values stored in a monomorphized map pointer type.
    fn map_value_c_ty(&self, map_c_ty: &str) -> Option<String> {
        if let Some((_, tag)) = parse_map_slice_val(map_c_ty) {
            return Some(if tag.starts_with("tup_") {
                format!("MakoTup_{}", &tag["tup_".len()..])
            } else {
                map_slice_val_c_ty(&tag)
            });
        }
        if let Some((_, tag)) = parse_map_k_slice_val(map_c_ty) {
            return Some(if tag.starts_with("tup_") {
                format!("MakoTup_{}", &tag["tup_".len()..])
            } else {
                map_slice_val_c_ty(&tag)
            });
        }
        // MakoMapS_tup_int_opt_string* etc. not caught above when tag starts with tup_
        // — parse_map_slice_val already handles tup_.
        None
    }

    /// True when two tuple C types have the same field C types (layout-compatible).
    fn tuple_fields_layout_eq(&self, a: &str, b: &str) -> bool {
        match (self.tuple_fields.get(a), self.tuple_fields.get(b)) {
            (Some(fa), Some(fb)) => fa == fb,
            _ => false,
        }
    }

    /// Mono tag fragment for an Option/Result value inside a tuple lit
    /// (`opt_int`, `res_string`, `opt_chan_Point`, …).
    fn tuple_bag_mono_tag(&self, temp: &str, is_option: bool) -> String {
        let pref = if is_option { "opt" } else { "res" };
        let kind = if is_option {
            self.option_some_kinds.get(temp).map(|s| s.as_str())
        } else {
            self.result_ok_kinds.get(temp).map(|s| s.as_str())
        };
        match kind.unwrap_or("int") {
            "int" | "bool" => format!("{pref}_int"),
            "string" => format!("{pref}_string"),
            "float" => format!("{pref}_float"),
            "chan_int" | "chan_bool" => format!("{pref}_chan_int"),
            "chan_string" => format!("{pref}_chan_string"),
            "chan_float" => format!("{pref}_chan_float"),
            "chan_struct" => {
                let sn = if is_option {
                    self.option_some_structs.get(temp)
                } else {
                    self.result_ok_structs.get(temp)
                };
                sn.map(|s| format!("{pref}_chan_{s}"))
                    .unwrap_or_else(|| format!("{pref}_chan_int"))
            }
            "struct" => {
                let sn = if is_option {
                    self.option_some_structs.get(temp)
                } else {
                    self.result_ok_structs.get(temp)
                };
                sn.map(|s| format!("{pref}_{s}"))
                    .unwrap_or_else(|| format!("{pref}_int"))
            }
            other if other.starts_with("chan_") => format!("{pref}_{other}"),
            _ => format!("{pref}_int"),
        }
    }

    /// Register metadata for a nested Result payload tag (`res_int`, `res_chan_Point`,
    /// `res_opt_int`, …) onto a temp that is either Option[Result[…]] or Result[Result[…]].
    fn register_nested_result_payload(&mut self, temp: &str, res_tag: &str) {
        // res_tag is the full `res_…` mono tag of the nested Result.
        let rest = res_tag.strip_prefix("res_").unwrap_or(res_tag);
        let ok_kind: String = match rest {
            "int" | "bool" => "int".into(),
            "string" => "string".into(),
            "float" => "float".into(),
            other if other.starts_with("opt_") => {
                // Result[Option[…]] nested inside outer bag: res_opt_int / res_opt_chan_int
                let chain = bag_opt_tag_to_chain(other);
                if let Some((first, restc)) = chain.split_first() {
                    // After Ok of nested Result, Option Some-kind is first.
                    // Stash for option_result_option_leafs / result_option when unboxing.
                    self.option_result_option_leafs
                        .insert(temp.to_string(), first.clone());
                    if first.as_str() == "option" && !restc.is_empty() {
                        // deeper Option nest after the first
                        if let Some(leaf) = restc.last() {
                            // keep leaf for Option[Result[Option[Option[T]]]] if needed
                            let _ = leaf;
                        }
                    }
                    // Also set result_option_inners shape used when Option unboxes to Result
                    // with Ok kind "option".
                    self.result_option_inners
                        .insert(temp.to_string(), first.clone());
                    if !restc.is_empty() {
                        self.result_option_chains
                            .insert(temp.to_string(), restc.to_vec());
                    }
                }
                "option".into()
            }
            other if other.starts_with("chan_") => {
                if other == "chan_float" {
                    "chan_float".into()
                } else if other == "chan_string" {
                    "chan_string".into()
                } else if other == "chan_bool" || other == "chan_int" {
                    other.to_string()
                } else {
                    let sn = &other["chan_".len()..];
                    self.result_ok_structs
                        .insert(temp.to_string(), sn.to_string());
                    self.option_some_structs
                        .insert(temp.to_string(), sn.to_string());
                    "chan_struct".into()
                }
            }
            other if other.starts_with("res_") => {
                // Result[Result[Result[…]]] — rare; treat as nested result
                self.result_result_inners
                    .insert(temp.to_string(), "result".into());
                "result".into()
            }
            other => {
                // named struct / enum leaf
                self.result_ok_structs
                    .insert(temp.to_string(), other.to_string());
                self.option_some_structs
                    .insert(temp.to_string(), other.to_string());
                "struct".into()
            }
        };
        // Outer bag is Option → option_result_inners; outer is Result → result_result_inners.
        // Both maps are consulted by the matching paths.
        self.option_result_inners
            .insert(temp.to_string(), ok_kind.clone());
        self.result_result_inners
            .insert(temp.to_string(), ok_kind);
    }

    fn push_share_scope(&mut self) {
        self.share_scopes.push(Vec::new());
        self.fn_env_scopes.push(Vec::new());
    }

    /// Emit a bounds check unless inside `unsafe { }`.
    /// Safe Mako indexing remains checked in optimized builds; only explicit
    /// unsafe code skips this emission.
    fn emit_bounds_check(&mut self, cond_c: &str, msg: &str) {
        if self.unsafe_depth > 0 {
            return;
        }
        self.line(&format!("MAKO_BOUNDS_CHECK({cond_c}, \"{msg}\");"));
    }

    fn pop_share_scope(&mut self) {
        // Drop MakoFn capture envs before share drops.
        if let Some(names) = self.fn_env_scopes.pop() {
            for name in names.into_iter().rev() {
                if self.fn_env_live.remove(&name) {
                    self.emit_line(format_args!("mako_fn_drop(&{name});"));
                }
            }
        }
        if let Some(names) = self.share_scopes.pop() {
            for name in names.into_iter().rev() {
                if self.share_live.remove(&name) {
                    self.emit_line(format_args!("mako_share_drop({name});"));
                }
            }
        }
    }

    fn register_share_local(&mut self, name: &str) {
        self.share_live.insert(name.to_string());
        if let Some(scope) = self.share_scopes.last_mut() {
            scope.push(name.to_string());
        }
    }

    fn note_share_dropped(&mut self, name: &str) {
        self.share_live.remove(name);
        // Keep name in share_scopes so pop is a no-op for already-dropped.
    }

    fn register_fn_env_local(&mut self, name: &str) {
        self.fn_env_live.insert(name.to_string());
        if let Some(scope) = self.fn_env_scopes.last_mut() {
            scope.push(name.to_string());
        }
    }

    fn note_fn_env_dropped(&mut self, name: &str) {
        self.fn_env_live.remove(name);
    }

    /// Emit a Go-like test harness that runs each `TestXxx` via `mako_test_run`.
    pub fn with_tests(mut self, tests: Vec<String>) -> Self {
        self.test_fns = Some(tests);
        self
    }

    fn fresh(&mut self, prefix: &str) -> String {
        let id = self.tmp;
        self.tmp += 1;
        format!("{prefix}_{id}")
    }

    fn emit_byte_array_lit(&mut self, elems: &[Expr]) -> (String, String) {
        let tmp = self.fresh("barr");
        let vals: Vec<String> = elems
            .iter()
            .map(|e| {
                let (_, v) = self.emit_expr(e);
                v
            })
            .collect();
        let lit = self.fresh("blit");
        let body = if vals.is_empty() {
            "0".to_string()
        } else {
            vals.join(", ")
        };
        self.line(&format!("int64_t {lit}[] = {{ {body} }};"));
        self.line(&format!(
            "MakoByteArray {tmp} = mako_byte_array_of({lit}, {});",
            elems.len()
        ));
        ("MakoByteArray".into(), tmp)
    }

    fn emit_str_array_lit(&mut self, elems: &[Expr]) -> (String, String) {
        let tmp = self.fresh("sarr");
        let vals: Vec<String> = elems
            .iter()
            .map(|e| {
                let (_, v) = self.emit_expr(e);
                v
            })
            .collect();
        let lit = self.fresh("slit");
        let body = if vals.is_empty() {
            "{NULL, 0}".to_string()
        } else {
            vals.join(", ")
        };
        self.line(&format!("MakoString {lit}[] = {{ {body} }};"));
        self.line(&format!(
            "MakoStrArray {tmp} = mako_str_array_of({lit}, {});",
            elems.len()
        ));
        ("MakoStrArray".into(), tmp)
    }

    fn emit_float_array_lit(&mut self, elems: &[Expr]) -> (String, String) {
        let tmp = self.fresh("farr");
        let vals: Vec<String> = elems
            .iter()
            .map(|e| {
                let (_, v) = self.emit_expr(e);
                v
            })
            .collect();
        let lit = self.fresh("flit");
        let body = if vals.is_empty() {
            "0.0".to_string()
        } else {
            vals.join(", ")
        };
        self.line(&format!("double {lit}[] = {{ {body} }};"));
        self.line(&format!(
            "MakoFloatArray {tmp} = mako_float_array_of({lit}, {});",
            elems.len()
        ));
        ("MakoFloatArray".into(), tmp)
    }

    fn emit_bool_array_lit(&mut self, elems: &[Expr]) -> (String, String) {
        let tmp = self.fresh("barr");
        let vals: Vec<String> = elems
            .iter()
            .map(|e| {
                let (_, v) = self.emit_expr(e);
                v
            })
            .collect();
        let lit = self.fresh("blit");
        let body = if vals.is_empty() {
            "false".to_string()
        } else {
            vals.join(", ")
        };
        self.line(&format!("bool {lit}[] = {{ {body} }};"));
        self.line(&format!(
            "MakoBoolArray {tmp} = mako_bool_array_of({lit}, {});",
            elems.len()
        ));
        ("MakoBoolArray".into(), tmp)
    }

    fn emit_struct_array_lit(&mut self, sn: &str, elems: &[Expr]) -> (String, String) {
        let tmp = self.fresh("sarr");
        let lit = self.fresh("slit");
        let arr_ty = format!("MakoArr_{sn}");
        if elems.is_empty() {
            self.line(&format!("{arr_ty} {tmp} = mako_arr_{sn}_make(0, 0);"));
            return (arr_ty, tmp);
        }
        self.line(&format!("{sn} {lit}[{}] ;", elems.len()));
        for (i, e) in elems.iter().enumerate() {
            let (_, v) = self.emit_expr(e);
            self.line(&format!("{lit}[{i}] = {v};"));
        }
        self.line(&format!(
            "{arr_ty} {tmp} = mako_arr_{sn}_of({lit}, {});",
            elems.len()
        ));
        (arr_ty, tmp)
    }

    fn line(&mut self, s: &str) {
        for _ in 0..self.indent {
            self.out.push_str("    ");
        }
        self.out.push_str(s);
        self.out.push('\n');
    }

    /// Write a formatted line directly into `self.out` without allocating an
    /// intermediate `String`.  Callers use `format_args!` which builds a
    /// stack-local `Arguments` struct — no heap allocation required.
    fn emit_line(&mut self, args: std::fmt::Arguments<'_>) {
        for _ in 0..self.indent {
            self.out.push_str("    ");
        }
        let _ = std::fmt::Write::write_fmt(&mut self.out, args);
        self.out.push('\n');
    }

    pub fn emit(mut self, program: &Program) -> String {
        // Native builds pull the full runtime surface. WASI preview1 builds
        // (`-DMAKO_WASI`) keep only `mako_rt.h` — sockets/TLS/DB need host POSIX.
        self.out.push_str("#include \"mako_rt.h\"\n");
        // Overflow mode for checked integer ops (must precede mako_overflow.h use).
        self.out.push_str(&format!(
            "#define MAKO_OVERFLOW_MODE {}\n",
            self.overflow_mode.c_define_value()
        ));
        // Preserve the legacy flag in generated C; safe indexing is checked
        // regardless of optimization level.
        if self.bounds_checks_always {
            self.out.push_str("#define MAKO_BOUNDS_ALWAYS 1\n");
        }
        self.out.push_str("#include \"mako_overflow.h\"\n");
        self.out.push_str("#ifndef MAKO_WASI\n");
        self.out.push_str("#include \"mako_uuid.h\"\n");
        self.out.push_str("#include \"mako_net.h\"\n");
        self.out.push_str("#include \"mako_proxy.h\"\n");
        self.out.push_str("#include \"mako_http.h\"\n");
        self.out.push_str("#include \"mako_trace.h\"\n"); /* before log/std so log_* can emit trace= */
        self.out.push_str("#include \"mako_log.h\"\n");   /* strong structured logging */
        self.out.push_str("#include \"mako_std.h\"\n");
        self.out.push_str("#include \"mako_leak.h\"\n");
        self.out.push_str("#include \"mako_shutdown.h\"\n");
        self.out.push_str("#include \"mako_tls.h\"\n");
        self.out.push_str("#include \"mako_llm.h\"\n");
        self.out.push_str("#include \"mako_sip.h\"\n");
        self.out.push_str("#include \"mako_nghttp2.h\"\n");
        self.out.push_str("#include \"mako_quiche.h\"\n");
        self.out.push_str("#include \"mako_ws.h\"\n");
        self.out.push_str("#include \"mako_db.h\"\n");
        self.out.push_str("#include \"mako_cmap.h\"\n");
        self.out.push_str("#include \"mako_dio.h\"\n");
        self.out.push_str("#include \"mako_domain.h\"\n");
        self.out.push_str("#include \"mako_evloop.h\"\n");
        self.out.push_str("#include \"mako_game.h\"\n");
        self.out.push_str("#include \"mako_gpu.h\"\n");
        self.out.push_str("#include \"mako_model.h\"\n");
        self.out.push_str("#include \"mako_tok.h\"\n");
        self.out.push_str("#include \"mako_mail.h\"\n");
        self.out.push_str("#include \"mako_template.h\"\n");
        self.out.push_str("#include \"mako_fmt.h\"\n");
        self.out.push_str("#include \"mako_cloud.h\"\n");
        self.out.push_str("#include \"mako_httpengine.h\"\n");
        self.out.push_str("#endif /* MAKO_WASI */\n\n");

        // Collect interfaces for method dispatch sugar
        for item in &program.items {
            if let Item::Interface(iface) = item {
                let methods: Vec<String> =
                    iface.methods.iter().map(|(n, _, _)| n.clone()).collect();
                self.interfaces.push((iface.name.clone(), methods));
            }
        }

        // Register enums + structs first so demand collection can resolve names.
        // Skip generic templates (non-empty type_params) — only monomorphized instances.
        for item in &program.items {
            if let Item::Enum(e) = item {
                if e.type_params.is_empty() {
                    self.register_enum(e);
                }
            }
        }
        for item in &program.items {
            if let Item::Struct(s) = item {
                if s.type_params.is_empty() {
                    self.register_struct(s);
                }
            }
        }
        // Demand-driven monomorphs: only emit map helpers used in this unit.
        self.collect_used_maps(program);
        // Build joined lookup set for O(1) want_map without per-call allocation.
        self.used_maps_joined = self.used_maps.iter()
            .map(|(k, v)| Self::map_join_key(k, v))
            .collect();
        // Emit C tagged unions + map monomorphs (gated by used_maps).
        for item in &program.items {
            if let Item::Enum(e) = item {
                if e.type_params.is_empty() {
                    self.emit_enum_typedef(e);
                }
            }
        }
        // Emit C structs + []T helpers + gated scalar-key maps.
        for item in &program.items {
            if let Item::Struct(s) = item {
                if s.type_params.is_empty() {
                    self.emit_struct_typedef(s);
                }
            }
        }
        // map[StructA]StructB after all []T / mako_eq / scalar-key helpers exist.
        self.emit_all_struct_key_struct_val_maps();
        self.emit_all_map_slice_value_helpers();
        self.emit_all_map_map_value_helpers();
        self.emit_all_map_option_result_helpers();
        self.emit_all_map_tuple_value_helpers();
        self.emit_all_map_chan_value_helpers();
        // Register Mako struct schemas for reflect_type_schema / reflect_value_of_type.
        for item in &program.items {
            if let Item::Struct(s) = item {
                self.emit_struct_reflect_schema(s);
            }
        }

        // Collect fn metadata first so iface fat pointers can use signatures,
        // then emit iface typedefs before forward declarations that reference them.
        for item in &program.items {
            match item {
                Item::Fn(f) => {
                    if !f.type_params.is_empty() {
                        self.generic_templates.insert(f.name.clone(), f.clone());
                        continue; // templates are not emitted; mono specializations are
                    }
                    let ret = self.c_ret_type_resolved(f);
                    self.fn_rets.insert(f.name.clone(), ret);
                    if let Some(rt) = f.ret.as_ref() {
                        if let Some(ec) = self.result_err_enum_c(rt) {
                            self.fn_result_err_enum.insert(f.name.clone(), ec);
                        }
                        if matches!(rt, TypeExpr::Generic(n, _) if n == "Result") {
                            self.fn_result_ok_kind
                                .insert(f.name.clone(), Self::result_ok_kind(rt).into());
                            if let Some(sn) = self.result_ok_struct_name(rt) {
                                self.fn_result_ok_struct.insert(f.name.clone(), sn);
                            }
                            if let Some(ik) = Self::result_option_inner_kind(rt) {
                                self.fn_result_option_inner
                                    .insert(f.name.clone(), ik.into());
                            }
                            let chain = Self::option_nest_chain_for_type(rt);
                            if !chain.is_empty() {
                                self.fn_result_option_chain
                                    .insert(f.name.clone(), chain);
                            }
                            if let Some(rik) = Self::result_result_inner_kind(rt) {
                                self.fn_result_result_inner
                                    .insert(f.name.clone(), rik.into());
                            }
                            if let TypeExpr::Generic(n, args) = rt {
                                if n == "Result" && !args.is_empty() {
                                    let deep = Self::successive_nest_kinds(&args[0]);
                                    if !deep.is_empty() {
                                        self.fn_deep_nest_chain
                                            .insert(f.name.clone(), deep);
                                    }
                                }
                            }
                        }
                        if matches!(rt, TypeExpr::Generic(n, _) if n == "Option") {
                            self.fn_option_some_kind
                                .insert(f.name.clone(), Self::option_some_kind(rt).into());
                            if let Some(sn) = self.option_some_struct_name(rt) {
                                self.fn_option_some_struct.insert(f.name.clone(), sn);
                            }
                            let chain = Self::option_nest_chain_for_type(rt);
                            if !chain.is_empty() {
                                self.fn_option_chain.insert(f.name.clone(), chain);
                            }
                            if let Some(rik) = Self::option_result_inner_kind(rt) {
                                self.fn_option_result_inner
                                    .insert(f.name.clone(), rik.into());
                            }
                            if let Some(leaf) = Self::option_result_option_leaf_kind(rt) {
                                self.fn_option_result_option_leaf
                                    .insert(f.name.clone(), leaf.into());
                            }
                            if let TypeExpr::Generic(n, args) = rt {
                                if n == "Option" && !args.is_empty() {
                                    let deep = Self::successive_nest_kinds(&args[0]);
                                    if !deep.is_empty() {
                                        self.fn_deep_nest_chain
                                            .insert(f.name.clone(), deep);
                                    }
                                }
                            }
                        }
                        // Result[Option[Result[…]]] also registers option→result metadata
                        if matches!(rt, TypeExpr::Generic(n, _) if n == "Result") {
                            if let Some(rik) = Self::option_result_inner_kind(rt) {
                                self.fn_option_result_inner
                                    .entry(f.name.clone())
                                    .or_insert_with(|| rik.into());
                            }
                            if let Some(leaf) = Self::option_result_option_leaf_kind(rt) {
                                self.fn_option_result_option_leaf
                                    .entry(f.name.clone())
                                    .or_insert_with(|| leaf.into());
                            }
                        }
                    }
                    let param_tys: Vec<String> =
                        f.params.iter().map(|p| self.type_expr_c(&p.ty)).collect();
                    self.fn_params.insert(f.name.clone(), param_tys);
                    // Track mut self methods for pointer-based dispatch
                    if let Some(first) = f.params.first() {
                        if first.name == "self" && first.mutable {
                            self.mut_self_fns.insert(f.name.clone());
                        }
                    }
                    self.fn_param_typeexprs.insert(
                        f.name.clone(),
                        f.params.iter().map(|p| p.ty.clone()).collect(),
                    );
                    if let Some(ec) = f.ret.as_ref().and_then(|t| self.result_err_enum_c(t)) {
                        self.fn_result_err_enum.insert(f.name.clone(), ec);
                    }
                    if f.is_const {
                        self.const_fns.insert(f.name.clone(), f.clone());
                    }
                }
                Item::ExternC(ext) => {
                    let ret = ext
                        .ret
                        .as_ref()
                        .map(|t| self.type_expr_c(t))
                        .unwrap_or_else(|| "void".into());
                    self.fn_rets.insert(ext.name.clone(), ret);
                    self.fn_params.insert(
                        ext.name.clone(),
                        ext.params.iter().map(|p| self.type_expr_c(&p.ty)).collect(),
                    );
                    self.extern_fns.insert(ext.name.clone());
                }
                _ => {}
            }
        }

        // Fat-pointer interface typedefs (before forward decls that use them)
        self.emit_iface_typedefs();

        // Source map seed for debuggers (maps generated C back to .mko)
        if let Some(src) = &self.source_file {
            let _ = writeln!(self.out, "#line 1 \"{}\"", escape_c(src));
        }

        // Hoist all tuple typedefs needed by signatures (and known literal tuples).
        self.predeclare_tuples(program);

        // Forward declarations
        for item in &program.items {
            match item {
                Item::Fn(f) => {
                    if !f.type_params.is_empty() {
                        continue;
                    }
                    let ret = self
                        .fn_rets
                        .get(&f.name)
                        .cloned()
                        .unwrap_or_else(|| "void".into());
                    let params = self.c_params_resolved(f);
                    let _ = writeln!(self.out, "{ret} {name}({params});", name = mangle(&f.name));
                }
                Item::ExternC(ext) => {
                    let ret = self
                        .fn_rets
                        .get(&ext.name)
                        .cloned()
                        .unwrap_or_else(|| "void".into());
                    let params = if ext.params.is_empty() {
                        "void".into()
                    } else {
                        ext.params
                            .iter()
                            .map(|p| format!("{} {}", self.type_expr_c(&p.ty), p.name))
                            .collect::<Vec<_>>()
                            .join(", ")
                    };
                    let _ = writeln!(self.out, "extern {ret} {name}({params});", name = ext.name);
                }
                _ => {}
            }
        }

        // Vtable wrappers need forward decls of Iface_method impls
        self.emit_iface_vtables();

        self.out.push_str("\n/*__MAKO_HELPERS__*/\n\n");

        for item in &program.items {
            match item {
                Item::Fn(f) => {
                    if f.type_params.is_empty() {
                        self.emit_fn(f);
                    }
                }
                Item::Struct(_)
                | Item::Enum(_)
                | Item::Actor(_)
                | Item::Interface(_)
                | Item::On(_)
                | Item::Package { .. }
                | Item::Import { .. } => {}
                Item::ExternC(_) => {}
                Item::Const(c) => {
                    if let Some(v) =
                        fold_const_c_env(&c.value, &self.const_ints, &self.const_strs, &self.const_fns)
                    {
                        self.const_ints.insert(c.name.clone(), v);
                        // Emit as #define so uses in C are valid integer constants
                        let _ = writeln!(
                            self.out,
                            "#define {} ((int64_t){})",
                            mangle(&c.name),
                            v
                        );
                    } else if let Some(s) =
                        fold_const_c_str(&c.value, &self.const_ints, &self.const_strs, &self.const_fns)
                    {
                        self.const_strs.insert(c.name.clone(), s);
                        // String consts are substituted at use sites (no #define).
                    }
                }
            }
        }

        if let Some(tests) = &self.test_fns {
            self.out.push_str("\nint main(int argc, char **argv) {\n");
            self.out.push_str("    mako_set_args(argc, argv);\n");
            self.out.push_str("    mako_test_install_crash_handler();\n");
            self.out.push_str("    int failed = 0;\n");
            for t in tests {
                let _ = writeln!(self.out, "    failed += mako_test_run(\"{t}\", {t});");
            }
            self.out.push_str(
                "    if (failed) {\n        fprintf(stderr, \"FAIL\\n\");\n        return 1;\n    }\n",
            );
            self.out
                .push_str("    printf(\"PASS\\n\");\n    fflush(stdout);\n    return 0;\n}\n");
        } else {
            self.out.push_str(
                "\nint main(int argc, char **argv) {\n    mako_set_args(argc, argv);\n    mako_main();\n    return 0;\n}\n",
            );
        }
        self.out
    }

    fn register_enum(&mut self, e: &EnumDef) {
        let c_name = format!("MakoEnum_{}", e.name);
        let mut variants = HashMap::new();
        for (i, v) in e.variants.iter().enumerate() {
            let fields: Vec<&'static str> = v
                .fields
                .iter()
                .map(|t| match t {
                    TypeExpr::Named(n) => match n.as_str() {
                        "string" => "string",
                        "bool" => "bool",
                        "float" => "float",
                        _ => "int",
                    },
                    _ => "int",
                })
                .collect();
            variants.insert(v.name.clone(), (i, fields));
            // First-wins for bare name; always register qualified for disambiguation
            if !self.variant_to_enum.contains_key(&v.name) {
                self.variant_to_enum.insert(v.name.clone(), e.name.clone());
            }
            self.variant_to_enum.insert(format!("{}::{}", e.name, v.name), e.name.clone());
        }
        self.enums
            .insert(e.name.clone(), EnumInfo { c_name, variants });
    }

    fn emit_enum_typedef(&mut self, e: &EnumDef) {
        let info = self.enums.get(&e.name).unwrap().clone();
        let c_name = info.c_name.clone();
        let _ = writeln!(self.out, "typedef struct {{");
        let _ = writeln!(self.out, "    int tag;");
        let _ = writeln!(self.out, "    int64_t i0;");
        let _ = writeln!(self.out, "    int64_t i1;");
        let _ = writeln!(self.out, "    int64_t i2;");
        let _ = writeln!(self.out, "    MakoString s0;");
        let _ = writeln!(self.out, "    MakoString s1;");
        let _ = writeln!(self.out, "}} {c_name};");
        // Structural equality: same tag + payload fields (strings by content).
        let _ = writeln!(
            self.out,
            "static inline bool mako_eq_{c_name}({c_name} a, {c_name} b) {{"
        );
        let _ = writeln!(self.out, "    if (a.tag != b.tag) return false;");
        // Build switch by tag index; field kinds from variant metadata.
        let mut by_tag: Vec<(usize, Vec<&str>)> = info
            .variants
            .iter()
            .map(|(_, (tag, fields))| (*tag, fields.clone()))
            .collect();
        by_tag.sort_by_key(|(t, _)| *t);
        if by_tag.iter().any(|(_, f)| !f.is_empty()) {
            let _ = writeln!(self.out, "    switch (a.tag) {{");
            for (tag, fields) in &by_tag {
                if fields.is_empty() {
                    let _ = writeln!(self.out, "    case {tag}: return true;");
                    continue;
                }
                let mut int_slot = 0usize;
                let mut str_slot = 0usize;
                let mut parts = Vec::new();
                for kind in fields {
                    match *kind {
                        "string" => {
                            parts.push(format!("mako_str_eq(a.s{str_slot}, b.s{str_slot})"));
                            str_slot += 1;
                        }
                        "float" => {
                            // floats stored as bits in i*
                            parts.push(format!("(a.i{int_slot} == b.i{int_slot})"));
                            int_slot += 1;
                        }
                        _ => {
                            parts.push(format!("(a.i{int_slot} == b.i{int_slot})"));
                            int_slot += 1;
                        }
                    }
                }
                let _ = writeln!(
                    self.out,
                    "    case {tag}: return {};",
                    parts.join(" && ")
                );
            }
            let _ = writeln!(self.out, "    default: return true;");
            let _ = writeln!(self.out, "    }}");
        } else {
            let _ = writeln!(self.out, "    return true;");
        }
        let _ = writeln!(self.out, "}}");
        // Hash for map keys: tag + all payload slots (unused slots are zero).
        let _ = writeln!(
            self.out,
            "static inline uint64_t mako_hash_{c_name}({c_name} k) {{"
        );
        let _ = writeln!(
            self.out,
            "    uint64_t h = 14695981039346656037ULL;"
        );
        let _ = writeln!(
            self.out,
            "    h ^= (uint64_t)(uint32_t)k.tag; h *= 1099511628211ULL;"
        );
        let _ = writeln!(
            self.out,
            "    h ^= (uint64_t)k.i0; h *= 1099511628211ULL;"
        );
        let _ = writeln!(
            self.out,
            "    h ^= (uint64_t)k.i1; h *= 1099511628211ULL;"
        );
        let _ = writeln!(
            self.out,
            "    h ^= (uint64_t)k.i2; h *= 1099511628211ULL;"
        );
        let _ = writeln!(
            self.out,
            "    h ^= mako_hash_bytes(k.s0.data ? k.s0.data : \"\", k.s0.data ? k.s0.len : 0); h *= 1099511628211ULL;"
        );
        let _ = writeln!(
            self.out,
            "    h ^= mako_hash_bytes(k.s1.data ? k.s1.data : \"\", k.s1.data ? k.s1.len : 0); h *= 1099511628211ULL;"
        );
        let _ = writeln!(self.out, "    return h;");
        let _ = writeln!(self.out, "}}");
        // []Enum + map monomorphization (same surface names as structs).
        self.emit_enum_array_and_maps(&e.name, &c_name);
        let _ = writeln!(self.out);
    }

    /// `[]Enum`, `map[scalar]Enum`, and `map[Enum]scalar` for a named enum.
    fn emit_enum_array_and_maps(&mut self, short: &str, c_ty: &str) {
        // --- []Enum ---
        let arr = format!("MakoArr_{short}");
        let _ = writeln!(self.out, "typedef struct {{");
        let _ = writeln!(self.out, "    {c_ty} *data;");
        let _ = writeln!(self.out, "    size_t len;");
        let _ = writeln!(self.out, "    size_t cap;");
        let _ = writeln!(self.out, "}} {arr};");
        let _ = writeln!(
            self.out,
            "static inline {arr} mako_arr_{short}_make(int64_t len, int64_t cap) {{"
        );
        let _ = writeln!(self.out, "    if (len < 0) len = 0;");
        let _ = writeln!(self.out, "    if (cap < len) cap = len;");
        let _ = writeln!(self.out, "    {arr} a;");
        let _ = writeln!(
            self.out,
            "    a.data = ({c_ty} *)calloc((size_t)(cap ? cap : 1), sizeof({c_ty}));"
        );
        let _ = writeln!(self.out, "    a.len = (size_t)len;");
        let _ = writeln!(self.out, "    a.cap = (size_t)(cap ? cap : 1);");
        let _ = writeln!(self.out, "    return a;");
        let _ = writeln!(self.out, "}}");
        let _ = writeln!(
            self.out,
            "static inline int64_t mako_arr_{short}_len({arr} a) {{ return (int64_t)a.len; }}"
        );
        let _ = writeln!(
            self.out,
            "static inline int64_t mako_arr_{short}_cap({arr} a) {{ return (int64_t)a.cap; }}"
        );
        let _ = writeln!(
            self.out,
            "static inline {c_ty} mako_arr_{short}_get({arr} a, int64_t i) {{"
        );
        let _ = writeln!(
            self.out,
            "    if (i < 0 || (size_t)i >= a.len) mako_abort(\"enum slice index out of bounds\");"
        );
        let _ = writeln!(self.out, "    return a.data[i];");
        let _ = writeln!(self.out, "}}");
        let _ = writeln!(
            self.out,
            "static inline void mako_arr_{short}_set({arr} a, int64_t i, {c_ty} v) {{"
        );
        let _ = writeln!(
            self.out,
            "    if (i < 0 || (size_t)i >= a.len) mako_abort(\"enum slice index out of bounds\");"
        );
        let _ = writeln!(self.out, "    a.data[i] = v;");
        let _ = writeln!(self.out, "}}");
        let _ = writeln!(
            self.out,
            "static inline {arr} mako_arr_{short}_append({arr} s, {c_ty} v) {{"
        );
        let _ = writeln!(self.out, "    if (s.len + 1 > s.cap) {{");
        let _ = writeln!(self.out, "        size_t ncap = s.cap ? s.cap * 2 : 1;");
        let _ = writeln!(self.out, "        if (ncap < s.len + 1) ncap = s.len + 1;");
        let _ = writeln!(
            self.out,
            "        {c_ty} *nd = ({c_ty} *)realloc(s.data, ncap * sizeof({c_ty}));"
        );
        let _ = writeln!(
            self.out,
            "        if (!nd) mako_abort(\"append: out of memory\");"
        );
        let _ = writeln!(self.out, "        s.data = nd; s.cap = ncap;");
        let _ = writeln!(self.out, "    }}");
        let _ = writeln!(self.out, "    s.data[s.len++] = v; return s;");
        let _ = writeln!(self.out, "}}");
        // Nested [][]Enum
        self.emit_nested_arr_helpers(&format!("arr_{short}"), &arr);

        // --- map[int|string|float|bool]Enum ---
        // Reuse the same monomorphized map[scalar]T emitter as structs, but with
        // enum C type + mako_eq/hash_MakoEnum_*.
        self.emit_named_value_map_helpers(short, c_ty);

        // --- map[Enum]int|string|float|bool ---
        let key_arr = format!("MakoArr_{short}");
        self.emit_named_key_map_helpers(short, c_ty, &key_arr);
    }

    /// map[int|string|float|bool]NamedValue for struct or enum short names.
    /// `short` is used in type/function names; `c_ty` is the C value type.
    fn emit_named_value_map_helpers(&mut self, short: &str, c_ty: &str) {
        // Only emit for enums here (structs already emit via emit_struct_map_helpers).
        // Int-key map — copy of map[int]T with parameterized names.
        if !self.want_scalar_val(short) {
            return;
        }
        let specs: &[(&str, &str, &str)] = &[
            ("I", "int64_t", "i"),
            ("S", "MakoString", "s"),
            ("F", "double", "f"),
            ("B", "bool", "b"),
        ];
        for (pref, key_c, key_suf) in specs {
            if !self.want_map(key_suf, short) {
                continue;
            }
            let mt = format!("MakoMap{pref}_{short}");
            let fnp = format!("mako_map_{key_suf}_{short}");
            let hash = if *key_suf == "i" {
                "mako_hash_i64(key)".to_string()
            } else if *key_suf == "s" {
                "mako_hash_bytes(key.data, key.len)".to_string()
            } else if *key_suf == "f" {
                "mako_hash_f64(key)".to_string()
            } else {
                "mako_hash_i64(key ? 1 : 0)".to_string()
            };
            let key_eq = if *key_suf == "s" {
                "mako_str_eq(m->keys[i], key)".to_string()
            } else if *key_suf == "f" {
                "mako_f64_key_eq(m->keys[i], key)".to_string()
            } else {
                "m->keys[i] == key".to_string()
            };
            let key_eq_get = if *key_suf == "s" {
                "mako_str_eq(m->keys[i], key)".to_string()
            } else if *key_suf == "f" {
                "mako_f64_key_eq(m->keys[i], key)".to_string()
            } else {
                "m->keys[i] == key".to_string()
            };
            let free_str_key = *key_suf == "s";

            let _ = writeln!(self.out, "typedef struct {{");
            let _ = writeln!(self.out, "    uint8_t *state;");
            let _ = writeln!(self.out, "    {key_c} *keys;");
            let _ = writeln!(self.out, "    {c_ty} *vals;");
            let _ = writeln!(self.out, "    size_t cap;");
            let _ = writeln!(self.out, "    size_t len;");
            let _ = writeln!(self.out, "}} {mt};");
            let _ = writeln!(
                self.out,
                "static inline {mt} {fnp}_new(size_t hint) {{"
            );
            let _ = writeln!(self.out, "    size_t cap = 8;");
            let _ = writeln!(
                self.out,
                "    size_t need = hint ? (hint * 4 / 3 + 1) : 8;"
            );
            let _ = writeln!(self.out, "    while (cap < need) cap *= 2;");
            let _ = writeln!(self.out, "    {mt} m;");
            let _ = writeln!(self.out, "    m.state = (uint8_t *)calloc(cap, 1);");
            if free_str_key {
                let _ = writeln!(
                    self.out,
                    "    m.keys = ({key_c} *)calloc(cap, sizeof({key_c}));"
                );
            } else {
                let _ = writeln!(
                    self.out,
                    "    m.keys = ({key_c} *)malloc(cap * sizeof({key_c}));"
                );
            }
            let _ = writeln!(
                self.out,
                "    m.vals = ({c_ty} *)calloc(cap, sizeof({c_ty}));"
            );
            let _ = writeln!(
                self.out,
                "    if (!m.keys || !m.vals) {{ fprintf(stderr, \"mako: OOM in {fnp}_new\\n\"); abort(); }}"
            );
            let _ = writeln!(self.out, "    m.cap = cap; m.len = 0; return m;");
            let _ = writeln!(self.out, "}}");
            let _ = writeln!(
                self.out,
                "static inline void {fnp}_rehash({mt} *m, size_t ncap);"
            );
            let _ = writeln!(
                self.out,
                "static inline void {fnp}_set({mt} *m, {key_c} key, {c_ty} val) {{"
            );
            if *key_suf == "f" {
                let _ = writeln!(self.out, "    key = mako_f64_key_norm(key);");
            }
            let _ = writeln!(
                self.out,
                "    if ((m->len + 1) * 4 >= m->cap * 3) {fnp}_rehash(m, m->cap * 2);"
            );
            let _ = writeln!(self.out, "    uint64_t h = {hash};");
            let _ = writeln!(self.out, "    size_t mask = m->cap - 1;");
            let _ = writeln!(self.out, "    size_t i = (size_t)(h & mask);");
            let _ = writeln!(self.out, "    size_t first_tomb = (size_t)-1;");
            let _ = writeln!(self.out, "    for (;;) {{");
            let _ = writeln!(self.out, "        uint8_t st = m->state[i];");
            let _ = writeln!(self.out, "        if (st == MAKO_MAP_EMPTY) {{");
            let _ = writeln!(
                self.out,
                "            size_t slot = (first_tomb != (size_t)-1) ? first_tomb : i;"
            );
            let _ = writeln!(self.out, "            m->state[slot] = MAKO_MAP_FULL;");
            if free_str_key {
                let _ = writeln!(
                    self.out,
                    "            m->keys[slot] = mako_str_clone(key);"
                );
            } else {
                let _ = writeln!(self.out, "            m->keys[slot] = key;");
            }
            let _ = writeln!(self.out, "            m->vals[slot] = val;");
            let _ = writeln!(self.out, "            m->len++; return;");
            let _ = writeln!(self.out, "        }}");
            let _ = writeln!(
                self.out,
                "        if (st == MAKO_MAP_TOMB) {{ if (first_tomb == (size_t)-1) first_tomb = i; }}"
            );
            let _ = writeln!(
                self.out,
                "        else if ({key_eq}) {{ m->vals[i] = val; return; }}"
            );
            let _ = writeln!(self.out, "        i = (i + 1) & mask;");
            let _ = writeln!(self.out, "    }}");
            let _ = writeln!(self.out, "}}");
            let _ = writeln!(
                self.out,
                "static inline void {fnp}_rehash({mt} *m, size_t ncap) {{"
            );
            let _ = writeln!(self.out, "    uint8_t *ostate = m->state;");
            let _ = writeln!(self.out, "    {key_c} *okeys = m->keys;");
            let _ = writeln!(self.out, "    {c_ty} *ovals = m->vals;");
            let _ = writeln!(self.out, "    size_t ocap = m->cap;");
            let _ = writeln!(self.out, "    {mt} n = {fnp}_new(ncap / 2);");
            let _ = writeln!(self.out, "    for (size_t i = 0; i < ocap; i++) {{");
            let _ = writeln!(self.out, "        if (ostate[i] != MAKO_MAP_FULL) continue;");
            let _ = writeln!(self.out, "        {key_c} key = okeys[i];");
            let _ = writeln!(self.out, "        {c_ty} val = ovals[i];");
            if *key_suf == "f" {
                let _ = writeln!(self.out, "        uint64_t h = mako_hash_f64(key);");
            } else if *key_suf == "s" {
                let _ = writeln!(
                    self.out,
                    "        uint64_t h = mako_hash_bytes(key.data, key.len);"
                );
            } else if *key_suf == "b" {
                let _ = writeln!(
                    self.out,
                    "        uint64_t h = mako_hash_i64(key ? 1 : 0);"
                );
            } else {
                let _ = writeln!(self.out, "        uint64_t h = mako_hash_i64(key);");
            }
            let _ = writeln!(self.out, "        size_t j = (size_t)(h & (n.cap - 1));");
            let _ = writeln!(
                self.out,
                "        while (n.state[j] == MAKO_MAP_FULL) j = (j + 1) & (n.cap - 1);"
            );
            let _ = writeln!(self.out, "        n.state[j] = MAKO_MAP_FULL;");
            let _ = writeln!(self.out, "        n.keys[j] = key; n.vals[j] = val; n.len++;");
            let _ = writeln!(self.out, "    }}");
            let _ = writeln!(self.out, "    free(ostate); free(okeys); free(ovals); *m = n;");
            let _ = writeln!(self.out, "}}");
            let _ = writeln!(
                self.out,
                "static inline {c_ty} {fnp}_get({mt} *m, {key_c} key) {{"
            );
            if *key_suf == "f" {
                let _ = writeln!(self.out, "    key = mako_f64_key_norm(key);");
            }
            let _ = writeln!(
                self.out,
                "    {c_ty} z; memset(&z, 0, sizeof(z)); if (!m) return z;"
            );
            let _ = writeln!(self.out, "    uint64_t h = {hash};");
            let _ = writeln!(self.out, "    size_t i = (size_t)(h & (m->cap - 1));");
            let _ = writeln!(self.out, "    for (;;) {{");
            let _ = writeln!(
                self.out,
                "        if (m->state[i] == MAKO_MAP_EMPTY) return z;"
            );
            let _ = writeln!(
                self.out,
                "        if (m->state[i] == MAKO_MAP_FULL && {key_eq_get}) return m->vals[i];"
            );
            let _ = writeln!(self.out, "        i = (i + 1) & (m->cap - 1);");
            let _ = writeln!(self.out, "    }}");
            let _ = writeln!(self.out, "}}");
            let _ = writeln!(
                self.out,
                "static inline bool {fnp}_has({mt} *m, {key_c} key) {{"
            );
            if *key_suf == "f" {
                let _ = writeln!(self.out, "    key = mako_f64_key_norm(key);");
            }
            let _ = writeln!(self.out, "    if (!m) return false;");
            let _ = writeln!(self.out, "    uint64_t h = {hash};");
            let _ = writeln!(self.out, "    size_t i = (size_t)(h & (m->cap - 1));");
            let _ = writeln!(self.out, "    for (;;) {{");
            let _ = writeln!(
                self.out,
                "        if (m->state[i] == MAKO_MAP_EMPTY) return false;"
            );
            let _ = writeln!(
                self.out,
                "        if (m->state[i] == MAKO_MAP_FULL && {key_eq_get}) return true;"
            );
            let _ = writeln!(self.out, "        i = (i + 1) & (m->cap - 1);");
            let _ = writeln!(self.out, "    }}");
            let _ = writeln!(self.out, "}}");
            let _ = writeln!(
                self.out,
                "static inline void {fnp}_delete({mt} *m, {key_c} key) {{"
            );
            if *key_suf == "f" {
                let _ = writeln!(self.out, "    key = mako_f64_key_norm(key);");
            }
            let _ = writeln!(self.out, "    if (!m) return;");
            let _ = writeln!(self.out, "    uint64_t h = {hash};");
            let _ = writeln!(self.out, "    size_t i = (size_t)(h & (m->cap - 1));");
            let _ = writeln!(self.out, "    for (;;) {{");
            let _ = writeln!(self.out, "        if (m->state[i] == MAKO_MAP_EMPTY) return;");
            let _ = writeln!(
                self.out,
                "        if (m->state[i] == MAKO_MAP_FULL && {key_eq_get}) {{"
            );
            if free_str_key {
                let _ = writeln!(
                    self.out,
                    "            mako_str_free(m->keys[i]); m->keys[i].data = NULL; m->keys[i].len = 0;"
                );
            }
            let _ = writeln!(
                self.out,
                "            m->state[i] = MAKO_MAP_TOMB; m->len--; return;"
            );
            let _ = writeln!(self.out, "        }}");
            let _ = writeln!(self.out, "        i = (i + 1) & (m->cap - 1);");
            let _ = writeln!(self.out, "    }}");
            let _ = writeln!(self.out, "}}");
            let _ = writeln!(
                self.out,
                "static inline int64_t {fnp}_len({mt} *m) {{ return m ? (int64_t)m->len : 0; }}"
            );
            let _ = writeln!(
                self.out,
                "static inline {mt} *{fnp}_make(int64_t hint) {{"
            );
            let _ = writeln!(
                self.out,
                "    {mt} *m = ({mt} *)malloc(sizeof({mt}));"
            );
            let _ = writeln!(
                self.out,
                "    *m = {fnp}_new(hint > 0 ? (size_t)hint : 0); return m;"
            );
            let _ = writeln!(self.out, "}}");
            // maps_*
            let keys_ret = match *key_suf {
                "s" => "MakoStrArray".to_string(),
                "f" => "MakoFloatArray".to_string(),
                "b" => "MakoBoolArray".to_string(),
                _ => "MakoIntArray".to_string(),
            };
            let keys_make = match *key_suf {
                "s" => "mako_str_array_make".to_string(),
                "f" => "mako_float_array_make".to_string(),
                "b" => "mako_bool_array_make".to_string(),
                _ => "mako_int_array_make".to_string(),
            };
            let keys_append = match *key_suf {
                "s" => format!(
                    "out = mako_str_array_append(out, m->keys[i]);"
                ),
                "f" => format!(
                    "out = mako_float_array_append(out, m->keys[i]);"
                ),
                "b" => format!(
                    "out = mako_bool_array_append(out, m->keys[i]);"
                ),
                _ => format!(
                    "if (out.len >= out.cap) {{ size_t ncap = out.cap ? out.cap * 2 : 8; out.data = (int64_t *)realloc(out.data, ncap * sizeof(int64_t)); out.cap = ncap; }} out.data[out.len++] = m->keys[i];"
                ),
            };
            let _ = writeln!(
                self.out,
                "static inline {keys_ret} mako_maps_keys_{key_suf}_{short}({mt} *m) {{"
            );
            let _ = writeln!(
                self.out,
                "    {keys_ret} out = {keys_make}(0, m ? (int64_t)m->len : 0);"
            );
            let _ = writeln!(self.out, "    if (!m) return out;");
            let _ = writeln!(self.out, "    for (size_t i = 0; i < m->cap; i++) {{");
            let _ = writeln!(self.out, "        if (m->state[i] == MAKO_MAP_FULL) {{ {keys_append} }}");
            let _ = writeln!(self.out, "    }} return out;");
            let _ = writeln!(self.out, "}}");
            let _ = writeln!(
                self.out,
                "static inline MakoArr_{short} mako_maps_values_{key_suf}_{short}({mt} *m) {{"
            );
            let _ = writeln!(
                self.out,
                "    MakoArr_{short} out = mako_arr_{short}_make(0, m ? (int64_t)m->len : 0);"
            );
            let _ = writeln!(self.out, "    if (!m) return out;");
            let _ = writeln!(self.out, "    for (size_t i = 0; i < m->cap; i++) {{");
            let _ = writeln!(
                self.out,
                "        if (m->state[i] == MAKO_MAP_FULL) out = mako_arr_{short}_append(out, m->vals[i]);"
            );
            let _ = writeln!(self.out, "    }} return out;");
            let _ = writeln!(self.out, "}}");
            let _ = writeln!(
                self.out,
                "static inline void mako_maps_clear_{key_suf}_{short}({mt} *m) {{"
            );
            if free_str_key {
                let _ = writeln!(self.out, "    if (!m) return;");
                let _ = writeln!(self.out, "    for (size_t i = 0; i < m->cap; i++) {{");
                let _ = writeln!(self.out, "        if (m->state[i] == MAKO_MAP_FULL) {{");
                let _ = writeln!(
                    self.out,
                    "            mako_str_free(m->keys[i]); m->keys[i].data = NULL; m->keys[i].len = 0;"
                );
                let _ = writeln!(self.out, "        }} m->state[i] = MAKO_MAP_EMPTY;");
                let _ = writeln!(self.out, "    }} m->len = 0;");
            } else {
                let _ = writeln!(
                    self.out,
                    "    if (!m) return; memset(m->state, 0, m->cap); m->len = 0;"
                );
            }
            let _ = writeln!(self.out, "}}");
            let _ = writeln!(
                self.out,
                "static inline {mt} *mako_maps_clone_{key_suf}_{short}({mt} *m) {{"
            );
            let _ = writeln!(
                self.out,
                "    {mt} *n = {fnp}_make(m ? (int64_t)m->len : 0);"
            );
            let _ = writeln!(self.out, "    if (!m) return n;");
            let _ = writeln!(self.out, "    for (size_t i = 0; i < m->cap; i++) {{");
            let _ = writeln!(self.out, "        if (m->state[i] == MAKO_MAP_FULL)");
            let _ = writeln!(
                self.out,
                "            {fnp}_set(n, m->keys[i], m->vals[i]);"
            );
            let _ = writeln!(self.out, "    }} return n;");
            let _ = writeln!(self.out, "}}");
            let _ = writeln!(
                self.out,
                "static inline int64_t mako_maps_equal_{key_suf}_{short}({mt} *a, {mt} *b) {{"
            );
            let _ = writeln!(
                self.out,
                "    if (!a && !b) return 1; if (!a || !b) return 0;"
            );
            let _ = writeln!(self.out, "    if (a->len != b->len) return 0;");
            let _ = writeln!(self.out, "    for (size_t i = 0; i < a->cap; i++) {{");
            let _ = writeln!(self.out, "        if (a->state[i] != MAKO_MAP_FULL) continue;");
            let _ = writeln!(
                self.out,
                "        if (!{fnp}_has(b, a->keys[i])) return 0;"
            );
            let _ = writeln!(
                self.out,
                "        if (!mako_eq_{c_ty}(a->vals[i], {fnp}_get(b, a->keys[i]))) return 0;"
            );
            let _ = writeln!(self.out, "    }} return 1;");
            let _ = writeln!(self.out, "}}");
            let _ = writeln!(
                self.out,
                "static inline void mako_maps_copy_{key_suf}_{short}({mt} *dst, {mt} *src) {{"
            );
            let _ = writeln!(self.out, "    if (!dst || !src) return;");
            let _ = writeln!(self.out, "    for (size_t i = 0; i < src->cap; i++) {{");
            let _ = writeln!(self.out, "        if (src->state[i] == MAKO_MAP_FULL)");
            let _ = writeln!(
                self.out,
                "            {fnp}_set(dst, src->keys[i], src->vals[i]);"
            );
            let _ = writeln!(self.out, "    }}");
            let _ = writeln!(self.out, "}}");
        }
    }

    /// map[NamedKey]int|string|float|bool (enum short name + C type).
    fn emit_named_key_map_helpers(&mut self, short: &str, c_ty: &str, key_arr: &str) {
        self.emit_key_map_helpers(short, c_ty, key_arr, /*struct_vals=*/ false);
    }

    fn register_struct(&mut self, s: &StructDef) {
        let c_name = s.name.clone();
        let fields: Vec<(String, String)> = s
            .fields
            .iter()
            .map(|(n, t, _)| (n.clone(), self.type_expr_c(t)))
            .collect();
        let mut defaults = HashMap::new();
        for (n, _, d) in &s.fields {
            if let Some(e) = d {
                defaults.insert(n.clone(), e.clone());
            }
        }
        self.structs.insert(
            s.name.clone(),
            StructInfo {
                c_name,
                fields,
                defaults,
            },
        );
    }

    fn emit_iface_typedefs(&mut self) {
        for (iname, methods) in self.interfaces.clone() {
            let iface_c = format!("MakoIface_{iname}");
            let vt_c = format!("MakoIface_{iname}_VTable");
            let _ = writeln!(self.out, "typedef struct {vt_c} {vt_c};");
            let _ = writeln!(self.out, "typedef struct {{");
            let _ = writeln!(self.out, "    void *data;");
            let _ = writeln!(self.out, "    const {vt_c} *vtable;");
            let _ = writeln!(self.out, "}} {iface_c};");
            let _ = writeln!(self.out, "struct {vt_c} {{");
            for m in &methods {
                // Prefer Iface_method; else Iface_Concrete_method; else Concrete_method (Go).
                let mut key = format!("{iname}_{m}");
                if !self.fn_params.contains_key(&key) {
                    let prefix = format!("{iname}_");
                    let suffix = format!("_{m}");
                    for fname in self.fn_params.keys() {
                        if let Some(rest) = fname.strip_prefix(&prefix) {
                            if let Some(cn) = rest.strip_suffix(&suffix) {
                                if !cn.is_empty() && !cn.contains('_') {
                                    key = fname.clone();
                                    break;
                                }
                            }
                        }
                    }
                }
                if !self.fn_params.contains_key(&key) {
                    for (sname, sinfo) in &self.structs {
                        let free = format!("{sname}_{m}");
                        let free_c = format!("{}_{m}", sinfo.c_name);
                        if self.fn_params.contains_key(&free) {
                            key = free;
                            break;
                        }
                        if self.fn_params.contains_key(&free_c) {
                            key = free_c;
                            break;
                        }
                    }
                }
                let ret = self
                    .fn_rets
                    .get(&key)
                    .cloned()
                    .unwrap_or_else(|| "int64_t".into());
                let params = self.fn_params.get(&key).cloned().unwrap_or_default();
                let arg_tys: Vec<String> =
                    if !params.is_empty()
                        && (self.structs.values().any(|s| s.c_name == params[0])
                            || self.structs.contains_key(&params[0]))
                    {
                        params[1..].to_vec()
                    } else {
                        params.clone()
                    };
                let mut sig = vec!["void *self".to_string()];
                for (i, t) in arg_tys.iter().enumerate() {
                    sig.push(format!("{t} a{i}"));
                }
                let _ = writeln!(self.out, "    {ret} (*{m})({});", sig.join(", "));
            }
            let _ = writeln!(self.out, "}};");
            let _ = writeln!(self.out);
        }
    }

    fn emit_iface_vtables(&mut self) {
        for (iname, methods) in self.interfaces.clone() {
            let mut concretes: Vec<String> = Vec::new();
            let mut has_no_self = false;
            for m in &methods {
                let prefix = format!("{iname}_");
                let suffix = format!("_{m}");
                for fname in self.fn_params.keys() {
                    if let Some(rest) = fname.strip_prefix(&prefix) {
                        if let Some(cn) = rest.strip_suffix(&suffix) {
                            if !cn.is_empty()
                                && !cn.contains('_')
                                && self.structs.values().any(|s| s.c_name == *cn)
                            {
                                if !concretes.iter().any(|c| c == cn) {
                                    concretes.push(cn.to_string());
                                }
                            }
                        }
                    }
                }
                let key = format!("{iname}_{m}");
                if let Some(params) = self.fn_params.get(&key) {
                    if let Some(p0) = params.first() {
                        if self.structs.values().any(|s| &s.c_name == p0) {
                            if !concretes.iter().any(|c| c == p0) {
                                concretes.push(p0.clone());
                            }
                        } else {
                            has_no_self = true;
                        }
                    } else {
                        has_no_self = true;
                    }
                }
                // Go-style method set: Struct_method (on Struct { fn m… } / free method).
                for (sname, sinfo) in &self.structs {
                    let free = format!("{sname}_{m}");
                    let free_c = format!("{}_{m}", sinfo.c_name);
                    let free_key = if self.fn_params.contains_key(&free) {
                        Some(free)
                    } else if self.fn_params.contains_key(&free_c) {
                        Some(free_c)
                    } else {
                        None
                    };
                    if let Some(fk) = free_key {
                        if let Some(params) = self.fn_params.get(&fk) {
                            if let Some(p0) = params.first() {
                                if p0 == &sinfo.c_name || p0 == sname {
                                    if !concretes.iter().any(|c| c == &sinfo.c_name) {
                                        concretes.push(sinfo.c_name.clone());
                                    }
                                }
                            }
                        }
                    }
                }
            }
            let iface_c = format!("MakoIface_{iname}");
            let vt_c = format!("MakoIface_{iname}_VTable");

            for concrete in &concretes {
                for m in &methods {
                    let keyed = format!("{iname}_{concrete}_{m}");
                    let iface_m = format!("{iname}_{m}");
                    // Source-name free method: map C concrete name back if needed.
                    let free = format!("{concrete}_{m}");
                    let free_src = self
                        .structs
                        .iter()
                        .find(|(_, s)| &s.c_name == concrete)
                        .map(|(n, _)| format!("{n}_{m}"));
                    let key = if self.fn_params.contains_key(&keyed) {
                        keyed
                    } else if self.fn_params.contains_key(&iface_m) {
                        // Prefer concrete-keyed Iface_method only when self matches;
                        // else fall through to free method for multi-concrete.
                        let params = self.fn_params.get(&iface_m).cloned().unwrap_or_default();
                        if params.first().map(|p| p == concrete).unwrap_or(false)
                            || params.is_empty()
                            || params
                                .first()
                                .map(|p| {
                                    !self.structs.values().any(|s| &s.c_name == p)
                                        && !self.structs.contains_key(p)
                                })
                                .unwrap_or(true)
                        {
                            iface_m
                        } else if self.fn_params.contains_key(&free) {
                            free
                        } else if let Some(ref fs) = free_src {
                            if self.fn_params.contains_key(fs) {
                                fs.clone()
                            } else {
                                iface_m
                            }
                        } else {
                            iface_m
                        }
                    } else if self.fn_params.contains_key(&free) {
                        free
                    } else if let Some(ref fs) = free_src {
                        if self.fn_params.contains_key(fs) {
                            fs.clone()
                        } else {
                            format!("{iname}_{m}")
                        }
                    } else {
                        format!("{iname}_{m}")
                    };
                    let ret = self
                        .fn_rets
                        .get(&key)
                        .cloned()
                        .unwrap_or_else(|| "int64_t".into());
                    let params = self.fn_params.get(&key).cloned().unwrap_or_default();
                    let has_self = !params.is_empty() && params[0] == *concrete;
                    let arg_tys: Vec<String> = if has_self {
                        params[1..].to_vec()
                    } else {
                        params.clone()
                    };
                    let wrap = format!("__mako_iface_{iname}_{m}_{concrete}");
                    let mut sig = vec!["void *self".to_string()];
                    let mut call_args = Vec::new();
                    if has_self {
                        call_args.push(format!("*({concrete} *)self"));
                    }
                    for (i, t) in arg_tys.iter().enumerate() {
                        sig.push(format!("{t} a{i}"));
                        call_args.push(format!("a{i}"));
                    }
                    let _ = writeln!(self.out, "static {ret} {wrap}({}) {{", sig.join(", "));
                    if ret == "void" {
                        let _ =
                            writeln!(self.out, "    {}({});", mangle(&key), call_args.join(", "));
                    } else {
                        let _ = writeln!(
                            self.out,
                            "    return {}({});",
                            mangle(&key),
                            call_args.join(", ")
                        );
                    }
                    let _ = writeln!(self.out, "}}");
                }
                let vt_inst = format!("MakoIface_{iname}_VTable_{concrete}");
                let _ = writeln!(self.out, "static const {vt_c} {vt_inst} = {{");
                for m in &methods {
                    let wrap = format!("__mako_iface_{iname}_{m}_{concrete}");
                    let _ = writeln!(self.out, "    .{m} = {wrap},");
                }
                let _ = writeln!(self.out, "}};");
                let box_fn = format!("mako_iface_{iname}_from_{concrete}");
                let _ = writeln!(
                    self.out,
                    "static inline {iface_c} {box_fn}({concrete} v) {{"
                );
                let _ = writeln!(
                    self.out,
                    "    {concrete} *p = ({concrete} *)malloc(sizeof({concrete}));"
                );
                let _ = writeln!(self.out, "    if (!p) mako_abort(\"iface box OOM\");");
                let _ = writeln!(self.out, "    *p = v;");
                let _ = writeln!(
                    self.out,
                    "    return ({iface_c}){{ .data = p, .vtable = &{vt_inst} }};"
                );
                let _ = writeln!(self.out, "}}");
            }

            if has_no_self || concretes.is_empty() {
                let mut ok_unit = !methods.is_empty();
                for m in &methods {
                    let key = format!("{iname}_{m}");
                    match self.fn_params.get(&key) {
                        Some(params)
                            if params
                                .first()
                                .map(|p| self.structs.values().any(|s| &s.c_name == p))
                                .unwrap_or(false) =>
                        {
                            ok_unit = false;
                        }
                        Some(_) => {}
                        None => ok_unit = false,
                    }
                }
                if ok_unit {
                    for m in &methods {
                        let key = format!("{iname}_{m}");
                        let ret = self
                            .fn_rets
                            .get(&key)
                            .cloned()
                            .unwrap_or_else(|| "int64_t".into());
                        let params = self.fn_params.get(&key).cloned().unwrap_or_default();
                        let wrap = format!("__mako_iface_{iname}_{m}_unit");
                        let mut sig = vec!["void *self".to_string()];
                        let mut call_args = Vec::new();
                        for (i, t) in params.iter().enumerate() {
                            sig.push(format!("{t} a{i}"));
                            call_args.push(format!("a{i}"));
                        }
                        let _ = writeln!(self.out, "static {ret} {wrap}({}) {{", sig.join(", "));
                        let _ = writeln!(self.out, "    (void)self;");
                        if ret == "void" {
                            let _ = writeln!(
                                self.out,
                                "    {}({});",
                                mangle(&key),
                                call_args.join(", ")
                            );
                        } else {
                            let _ = writeln!(
                                self.out,
                                "    return {}({});",
                                mangle(&key),
                                call_args.join(", ")
                            );
                        }
                        let _ = writeln!(self.out, "}}");
                    }
                    let vt_inst = format!("MakoIface_{iname}_VTable_unit");
                    let _ = writeln!(self.out, "static const {vt_c} {vt_inst} = {{");
                    for m in &methods {
                        let wrap = format!("__mako_iface_{iname}_{m}_unit");
                        let _ = writeln!(self.out, "    .{m} = {wrap},");
                    }
                    let _ = writeln!(self.out, "}};");
                    let box_fn = format!("mako_iface_{iname}_from_int64_t");
                    let _ = writeln!(self.out, "static inline {iface_c} {box_fn}(int64_t v) {{");
                    let _ = writeln!(self.out, "    (void)v;");
                    let _ = writeln!(
                        self.out,
                        "    return ({iface_c}){{ .data = NULL, .vtable = &{vt_inst} }};"
                    );
                    let _ = writeln!(self.out, "}}");
                }
            }
            let _ = writeln!(self.out);
        }
    }

    fn emit_struct_typedef(&mut self, s: &StructDef) {
        let info = self.structs.get(&s.name).unwrap().clone();
        let c_name = info.c_name.clone();
        let _ = writeln!(self.out, "typedef struct {{");
        for (fname, fty) in &info.fields {
            let _ = writeln!(self.out, "    {fty} {fname};");
        }
        let _ = writeln!(self.out, "}} {c_name};");
        // Structural equality (content for strings; field-wise for nested structs).
        // Slice/map/array fields use identity (data pointer + len) — not deep content.
        let _ = writeln!(
            self.out,
            "static inline bool mako_eq_{c_name}({c_name} a, {c_name} b) {{"
        );
        if info.fields.is_empty() {
            let _ = writeln!(self.out, "    (void)a; (void)b; return true;");
        } else {
            let mut parts = Vec::new();
            for (fname, fty) in &info.fields {
                let cmp = struct_field_eq_expr("a", "b", fname, fty, &self.structs);
                parts.push(cmp);
            }
            let _ = writeln!(self.out, "    return {};", parts.join(" && "));
        }
        let _ = writeln!(self.out, "}}");
        // Structural hash for use as map keys (FNV-1a over field hashes).
        // Composite fields (slices/maps) hash identity only so large engine
        // structs with []T / map fields still compile (map[HeavyStruct] is rare).
        let _ = writeln!(
            self.out,
            "static inline uint64_t mako_hash_{c_name}({c_name} k) {{"
        );
        let _ = writeln!(
            self.out,
            "    uint64_t h = 14695981039346656037ULL;"
        );
        if info.fields.is_empty() {
            let _ = writeln!(self.out, "    (void)k;");
        } else {
            for (fname, fty) in &info.fields {
                let step = struct_field_hash_step("k", fname, fty, &self.structs);
                let _ = writeln!(self.out, "    {step}");
            }
        }
        let _ = writeln!(self.out, "    return h;");
        let _ = writeln!(self.out, "}}");
        let arr = format!("MakoArr_{c_name}");
        let _ = writeln!(self.out, "typedef struct {{");
        let _ = writeln!(self.out, "    {c_name} *data;");
        let _ = writeln!(self.out, "    size_t len;");
        let _ = writeln!(self.out, "    size_t cap;");
        let _ = writeln!(self.out, "}} {arr};");
        let _ = writeln!(
            self.out,
            "static inline {arr} mako_arr_{c_name}_make(int64_t len, int64_t cap) {{"
        );
        let _ = writeln!(self.out, "    if (len < 0) len = 0;");
        let _ = writeln!(self.out, "    if (cap < len) cap = len;");
        let _ = writeln!(self.out, "    {arr} a;");
        let _ = writeln!(
            self.out,
            "    a.data = ({c_name} *)calloc((size_t)(cap ? cap : 1), sizeof({c_name}));"
        );
        let _ = writeln!(self.out, "    a.len = (size_t)len;");
        let _ = writeln!(self.out, "    a.cap = (size_t)(cap ? cap : 1);");
        let _ = writeln!(self.out, "    return a;");
        let _ = writeln!(self.out, "}}");
        let _ = writeln!(
            self.out,
            "static inline int64_t mako_arr_{c_name}_len({arr} a) {{ return (int64_t)a.len; }}"
        );
        let _ = writeln!(
            self.out,
            "static inline int64_t mako_arr_{c_name}_cap({arr} a) {{ return (int64_t)a.cap; }}"
        );
        let _ = writeln!(
            self.out,
            "static inline {c_name} mako_arr_{c_name}_get({arr} a, int64_t i) {{"
        );
        let _ = writeln!(
            self.out,
            "    if (i < 0 || (size_t)i >= a.len) mako_abort(\"struct slice index out of bounds\");"
        );
        let _ = writeln!(self.out, "    return a.data[i];");
        let _ = writeln!(self.out, "}}");
        let _ = writeln!(
            self.out,
            "static inline void mako_arr_{c_name}_set({arr} a, int64_t i, {c_name} v) {{"
        );
        let _ = writeln!(
            self.out,
            "    if (i < 0 || (size_t)i >= a.len) mako_abort(\"struct slice index out of bounds\");"
        );
        let _ = writeln!(self.out, "    a.data[i] = v;");
        let _ = writeln!(self.out, "}}");
        let _ = writeln!(
            self.out,
            "static inline {arr} mako_arr_{c_name}_append({arr} s, {c_name} v) {{"
        );
        let _ = writeln!(self.out, "    if (s.len + 1 > s.cap) {{");
        let _ = writeln!(self.out, "        size_t ncap = s.cap ? s.cap * 2 : 1;");
        let _ = writeln!(self.out, "        if (ncap < s.len + 1) ncap = s.len + 1;");
        let _ = writeln!(
            self.out,
            "        {c_name} *nd = ({c_name} *)realloc(s.data, ncap * sizeof({c_name}));"
        );
        let _ = writeln!(
            self.out,
            "        if (!nd) mako_abort(\"append: out of memory\");"
        );
        let _ = writeln!(self.out, "        s.data = nd;");
        let _ = writeln!(self.out, "        s.cap = ncap;");
        let _ = writeln!(self.out, "    }}");
        let _ = writeln!(self.out, "    s.data[s.len++] = v;");
        let _ = writeln!(self.out, "    return s;");
        let _ = writeln!(self.out, "}}");
        let _ = writeln!(
            self.out,
            "static inline {arr} mako_arr_{c_name}_arena_append(MakoArena *arena, {arr} s, {c_name} v) {{"
        );
        let _ = writeln!(self.out, "    if (s.len + 1 > s.cap) {{");
        let _ = writeln!(self.out, "        size_t ncap = s.cap ? s.cap * 2 : 1;");
        let _ = writeln!(self.out, "        if (ncap < s.len + 1) ncap = s.len + 1;");
        let _ = writeln!(
            self.out,
            "        {c_name} *nd = ({c_name} *)mako_arena_alloc(arena, ncap * sizeof({c_name}));"
        );
        let _ = writeln!(
            self.out,
            "        if (s.len) memcpy(nd, s.data, s.len * sizeof({c_name}));"
        );
        let _ = writeln!(self.out, "        s.data = nd;");
        let _ = writeln!(self.out, "        s.cap = ncap;");
        let _ = writeln!(self.out, "    }}");
        let _ = writeln!(self.out, "    s.data[s.len++] = v;");
        let _ = writeln!(self.out, "    return s;");
        let _ = writeln!(self.out, "}}");
        let _ = writeln!(
            self.out,
            "static inline {arr} mako_arr_{c_name}_of(const {c_name} *vals, size_t n) {{"
        );
        let _ = writeln!(
            self.out,
            "    {arr} a = mako_arr_{c_name}_make((int64_t)n, (int64_t)n);"
        );
        let _ = writeln!(
            self.out,
            "    if (n) memcpy(a.data, vals, n * sizeof({c_name}));"
        );
        let _ = writeln!(self.out, "    return a;");
        let _ = writeln!(self.out, "}}");
        let _ = writeln!(
            self.out,
            "static inline {arr} mako_arr_{c_name}_arena_make(MakoArena *arena, int64_t len, int64_t cap) {{"
        );
        let _ = writeln!(self.out, "    if (len < 0) len = 0;");
        let _ = writeln!(self.out, "    if (cap < len) cap = len;");
        let _ = writeln!(self.out, "    {arr} a;");
        let _ = writeln!(
            self.out,
            "    a.data = ({c_name} *)mako_arena_alloc(arena, (size_t)(cap ? cap : 1) * sizeof({c_name}));"
        );
        let _ = writeln!(
            self.out,
            "    memset(a.data, 0, (size_t)(cap ? cap : 1) * sizeof({c_name}));"
        );
        let _ = writeln!(self.out, "    a.len = (size_t)len;");
        let _ = writeln!(self.out, "    a.cap = (size_t)(cap ? cap : 1);");
        let _ = writeln!(self.out, "    return a;");
        let _ = writeln!(self.out, "}}");
        // Nested [][]Struct (elements are MakoArr_T).
        self.emit_nested_arr_helpers(&format!("arr_{c_name}"), &format!("MakoArr_{c_name}"));
        // Monomorphized maps: map[int]T and map[string]T for this struct.
        self.emit_struct_map_helpers(&c_name);
        let _ = writeln!(self.out);
    }

    /// Emit `MakoArr_{tag}` holding elements of C type `elem_c` (e.g. tag=arr_int, elem=MakoIntArray).
    fn emit_nested_arr_helpers(&mut self, tag: &str, elem_c: &str) {
        if !self.emitted_arr_tags.insert(tag.to_string()) {
            return;
        }
        let mt = format!("MakoArr_{tag}");
        let pref = format!("mako_arr_{tag}");
        let _ = writeln!(self.out, "typedef struct {{");
        let _ = writeln!(self.out, "    {elem_c} *data;");
        let _ = writeln!(self.out, "    size_t len;");
        let _ = writeln!(self.out, "    size_t cap;");
        let _ = writeln!(self.out, "}} {mt};");
        let _ = writeln!(
            self.out,
            "static inline {mt} {pref}_make(int64_t len, int64_t cap) {{"
        );
        let _ = writeln!(self.out, "    if (len < 0) len = 0;");
        let _ = writeln!(self.out, "    if (cap < len) cap = len;");
        let _ = writeln!(self.out, "    {mt} a;");
        let _ = writeln!(
            self.out,
            "    a.data = ({elem_c} *)calloc((size_t)(cap ? cap : 1), sizeof({elem_c}));"
        );
        let _ = writeln!(self.out, "    a.len = (size_t)len;");
        let _ = writeln!(self.out, "    a.cap = (size_t)(cap ? cap : 1);");
        let _ = writeln!(self.out, "    return a;");
        let _ = writeln!(self.out, "}}");
        let _ = writeln!(
            self.out,
            "static inline int64_t {pref}_len({mt} a) {{ return (int64_t)a.len; }}"
        );
        let _ = writeln!(
            self.out,
            "static inline int64_t {pref}_cap({mt} a) {{ return (int64_t)a.cap; }}"
        );
        let _ = writeln!(
            self.out,
            "static inline {elem_c} {pref}_get({mt} a, int64_t i) {{"
        );
        let _ = writeln!(
            self.out,
            "    if (i < 0 || (size_t)i >= a.len) mako_abort(\"nested slice index out of bounds\");"
        );
        let _ = writeln!(self.out, "    return a.data[i];");
        let _ = writeln!(self.out, "}}");
        let _ = writeln!(
            self.out,
            "static inline void {pref}_set({mt} a, int64_t i, {elem_c} v) {{"
        );
        let _ = writeln!(
            self.out,
            "    if (i < 0 || (size_t)i >= a.len) mako_abort(\"nested slice index out of bounds\");"
        );
        let _ = writeln!(self.out, "    a.data[i] = v;");
        let _ = writeln!(self.out, "}}");
        let _ = writeln!(
            self.out,
            "static inline {mt} {pref}_append({mt} s, {elem_c} v) {{"
        );
        let _ = writeln!(self.out, "    if (s.len + 1 > s.cap) {{");
        let _ = writeln!(self.out, "        size_t ncap = s.cap ? s.cap * 2 : 1;");
        let _ = writeln!(self.out, "        if (ncap < s.len + 1) ncap = s.len + 1;");
        let _ = writeln!(
            self.out,
            "        {elem_c} *nd = ({elem_c} *)realloc(s.data, ncap * sizeof({elem_c}));"
        );
        let _ = writeln!(
            self.out,
            "        if (!nd) mako_abort(\"append: out of memory\");"
        );
        let _ = writeln!(self.out, "        s.data = nd; s.cap = ncap;");
        let _ = writeln!(self.out, "    }}");
        let _ = writeln!(self.out, "    s.data[s.len++] = v; return s;");
        let _ = writeln!(self.out, "}}");
        let _ = writeln!(
            self.out,
            "static inline {mt} {pref}_of(const {elem_c} *vals, size_t n) {{"
        );
        let _ = writeln!(
            self.out,
            "    {mt} a = {pref}_make((int64_t)n, (int64_t)n);"
        );
        let _ = writeln!(
            self.out,
            "    if (n) memcpy(a.data, vals, n * sizeof({elem_c}));"
        );
        let _ = writeln!(self.out, "    return a;");
        let _ = writeln!(self.out, "}}");
        let _ = writeln!(
            self.out,
            "static inline {mt} {pref}_slice_expr({mt} s, int64_t low, int64_t high, int64_t max, int has_max) {{"
        );
        let _ = writeln!(self.out, "    int64_t len = (int64_t)s.len;");
        let _ = writeln!(self.out, "    int64_t cap = (int64_t)s.cap;");
        let _ = writeln!(self.out, "    if (low < 0) low = 0;");
        let _ = writeln!(self.out, "    if (high < 0) high = 0;");
        let _ = writeln!(self.out, "    if (low > len) low = len;");
        let _ = writeln!(self.out, "    if (high > len) high = len;");
        let _ = writeln!(self.out, "    if (high < low) high = low;");
        let _ = writeln!(self.out, "    {mt} out;");
        let _ = writeln!(self.out, "    out.data = s.data + (size_t)low;");
        let _ = writeln!(self.out, "    out.len = (size_t)(high - low);");
        let _ = writeln!(self.out, "    if (has_max) {{");
        let _ = writeln!(self.out, "        if (max < high) max = high;");
        let _ = writeln!(self.out, "        if (max > cap) max = cap;");
        let _ = writeln!(self.out, "        if (max < low) max = low;");
        let _ = writeln!(self.out, "        out.cap = (size_t)(max - low);");
        let _ = writeln!(self.out, "    }} else {{");
        let _ = writeln!(self.out, "        out.cap = (size_t)(cap - low);");
        let _ = writeln!(self.out, "    }}");
        let _ = writeln!(self.out, "    return out;");
        let _ = writeln!(self.out, "}}");
    }

    /// Emit all `map[scalar][]T` / `[][]T` and `map[Named][]T` / `[][]T` helpers.
    fn emit_all_map_slice_value_helpers(&mut self) {
        let keys: &[(&str, &str)] = &[
            ("i", "int64_t"),
            ("s", "MakoString"),
            ("f", "double"),
            ("b", "bool"),
        ];
        let mut vals: Vec<(String, String)> = vec![
            ("arr_int".into(), "MakoIntArray".into()),
            ("arr_string".into(), "MakoStrArray".into()),
            ("arr_float".into(), "MakoFloatArray".into()),
            ("arr_bool".into(), "MakoBoolArray".into()),
            ("arr_byte".into(), "MakoByteArray".into()),
            // Nested slice values: map[K][][]T (runtime has MakoArr_arr_{int,string,float,bool})
            ("arr_arr_int".into(), "MakoArr_arr_int".into()),
            ("arr_arr_string".into(), "MakoArr_arr_string".into()),
            ("arr_arr_float".into(), "MakoArr_arr_float".into()),
            ("arr_arr_bool".into(), "MakoArr_arr_bool".into()),
        ];
        let mut names: Vec<String> = self.structs.keys().cloned().collect();
        names.extend(self.enums.keys().cloned());
        names.sort();
        for n in &names {
            vals.push((format!("arr_{n}"), format!("MakoArr_{n}")));
            // map[K][][]Named — outer of MakoArr_N (from emit_nested on struct/enum)
            vals.push((format!("arr_arr_{n}"), format!("MakoArr_arr_{n}")));
        }
        // map[K][]Option[T] / map[K][]Result[T,E] — bag element slices (zero-cost monomorphs).
        // Also nested bag elements: []Option[Option[T]], []Option[Result[T]], []Result[Option[T]],
        // []Result[Result[T]] (scalar / struct / chan leaves).
        let mut bag_tags: Vec<(String, String)> = vec![
            ("opt_int".into(), "MakoOptionInt".into()),
            ("opt_string".into(), "MakoOptionInt".into()),
            ("opt_float".into(), "MakoOptionInt".into()),
            ("opt_bool".into(), "MakoOptionInt".into()),
            ("res_int".into(), "MakoResultInt".into()),
            ("res_string".into(), "MakoResultInt".into()),
            ("res_float".into(), "MakoResultInt".into()),
            ("res_bool".into(), "MakoResultInt".into()),
        ];
        for leaf in ["int", "string", "float", "bool"] {
            bag_tags.push((format!("opt_opt_{leaf}"), "MakoOptionInt".into()));
            bag_tags.push((format!("opt_res_{leaf}"), "MakoOptionInt".into()));
            bag_tags.push((format!("res_opt_{leaf}"), "MakoResultInt".into()));
            bag_tags.push((format!("res_res_{leaf}"), "MakoResultInt".into()));
        }
        for n in &names {
            bag_tags.push((format!("opt_{n}"), "MakoOptionInt".into()));
            bag_tags.push((format!("res_{n}"), "MakoResultInt".into()));
            bag_tags.push((format!("opt_opt_{n}"), "MakoOptionInt".into()));
            bag_tags.push((format!("opt_res_{n}"), "MakoOptionInt".into()));
            bag_tags.push((format!("res_opt_{n}"), "MakoResultInt".into()));
            bag_tags.push((format!("res_res_{n}"), "MakoResultInt".into()));
        }
        // map[K][]Option[chan[T]] / map[K][]Result[chan[T],E]
        // + nested: []Option[Option[chan]] / []Option[Result[chan]] / …
        for (ctag, _) in self.leaf_chan_value_specs() {
            bag_tags.push((format!("opt_{ctag}"), "MakoOptionInt".into()));
            bag_tags.push((format!("res_{ctag}"), "MakoResultInt".into()));
            bag_tags.push((format!("opt_opt_{ctag}"), "MakoOptionInt".into()));
            bag_tags.push((format!("opt_res_{ctag}"), "MakoOptionInt".into()));
            bag_tags.push((format!("res_opt_{ctag}"), "MakoResultInt".into()));
            bag_tags.push((format!("res_res_{ctag}"), "MakoResultInt".into()));
        }
        for (tag, elem_c) in &bag_tags {
            let arr_tag = format!("arr_{tag}");
            // Only emit []Option / []Result helpers when used as map values or slices.
            if self.want_arr_elem(tag) {
                self.emit_nested_arr_helpers(tag, elem_c); // MakoArr_opt_int
                vals.push((arr_tag, format!("MakoArr_{tag}")));
            }
        }
        // map[K][]map[…] — first ensure []map helpers (MakoArr_map_string_int), then
        // monomorphize maps that store those slices.
        let map_arr_tags: &[&str] = &[
            "map_string_int",
            "map_int_int",
            "map_string_string",
            "map_int_float",
            "map_string_float",
            "map_float_int",
            "map_float_string",
            "map_float_float",
            "map_int_bool",
            "map_string_bool",
            "map_float_bool",
            "map_bool_int",
            "map_bool_string",
            "map_bool_float",
            "map_bool_bool",
        ];
        for mt in map_arr_tags {
            let arr_tag = format!("arr_{mt}");
            // Bare `[]map[K]V` (used_arr_elems) or map[K]map / map[K][]map values.
            if self.want_arr_elem(mt) {
                let map_c = map_map_val_c_ty(mt);
                self.emit_nested_arr_helpers(mt, &map_c); // MakoArr_map_string_int
                vals.push((arr_tag, format!("MakoArr_{mt}")));
            }
        }
        // map[K][]chan[T] — slice of channel pointers (MakoArr_chan_int, …).
        // map[K][][]chan[T] — nested channel slices (MakoArr_arr_chan_int, …).
        let chan_leaf = self.leaf_chan_value_specs();
        for (ctag, cc) in &chan_leaf {
            self.emit_nested_arr_helpers(ctag, cc); // MakoArr_chan_int
            vals.push((format!("arr_{ctag}"), format!("MakoArr_{ctag}")));
            // Outer of []chan for [][]chan
            self.emit_nested_arr_helpers(
                &format!("arr_{ctag}"),
                &format!("MakoArr_{ctag}"),
            );
            vals.push((
                format!("arr_arr_{ctag}"),
                format!("MakoArr_arr_{ctag}"),
            ));
        }
        // Outer arrays for maps_values (MakoArr_arr_arr_int / MakoArr_arr_opt_… / …)
        for (vt, vc) in &vals {
            if vt.starts_with("arr_arr_")
                || vt.starts_with("arr_map_")
                || vt.starts_with("arr_opt_")
                || vt.starts_with("arr_res_")
                || vt.starts_with("arr_chan_")
            {
                self.emit_nested_arr_helpers(vt, vc);
            }
        }
        for (ks, kc) in keys {
            for (vt, vc) in &vals {
                if !self.want_map(ks, vt) {
                    continue;
                }
                self.emit_map_slice_value_helpers(ks, kc, vt, vc);
            }
        }
        // map[Struct|Enum][]T / [][]T
        let mut named_keys: Vec<(String, String)> = self
            .structs
            .iter()
            .map(|(n, s)| (n.clone(), s.c_name.clone()))
            .collect();
        for (n, info) in &self.enums {
            named_keys.push((n.clone(), info.c_name.clone()));
        }
        named_keys.sort_by(|a, b| a.0.cmp(&b.0));
        for (kname, kc) in &named_keys {
            if !self.want_named_key(kname) {
                continue;
            }
            for (vt, vc) in &vals {
                if !self.want_named_map(kname, vt) {
                    continue;
                }
                self.emit_map_named_key_slice_helpers(kname, kc, vt, vc);
            }
        }
    }

    /// Emit `map[K](T,U[,…])` monomorphs — tuple values by value (scalar 2–3-tuples).
    fn emit_all_map_tuple_value_helpers(&mut self) {
        let bases: &[(&str, &str)] = &[
            ("int", "int64_t"),
            ("string", "MakoString"),
            ("float", "double"),
            ("bool", "bool"),
        ];
        // 2-tuples and 3-tuples over scalar bases (zero-cost monomorph grid).
        let mut tags: Vec<(String, String, String, String)> = Vec::new();
        for (a, ac) in bases {
            for (b, bc) in bases {
                let tag = format!("tup_{a}_{b}");
                let cty = format!("MakoTup_{a}_{b}");
                // Ensure typedef exists.
                if self.note_tuple_typedef(&cty, vec![(*ac).into(), (*bc).into()]) {
                    let _ = writeln!(
                        self.out,
                        "typedef struct {{\n    {ac} _0;\n    {bc} _1;\n}} {cty};"
                    );
                }
                let zero = format!("(({cty}){{0}})");
                let eq0 = tuple_field_eq(ac, "av._0", "bv._0");
                let eq1 = tuple_field_eq(bc, "av._1", "bv._1");
                let eq = format!("({eq0} && {eq1})");
                tags.push((tag, cty, zero, eq));
            }
        }
        for (a, ac) in bases {
            for (b, bc) in bases {
                for (c, cc) in bases {
                    let tag = format!("tup_{a}_{b}_{c}");
                    let cty = format!("MakoTup_{a}_{b}_{c}");
                    if self.note_tuple_typedef(
                        &cty,
                        vec![(*ac).into(), (*bc).into(), (*cc).into()],
                    ) {
                        let _ = writeln!(
                            self.out,
                            "typedef struct {{\n    {ac} _0;\n    {bc} _1;\n    {cc} _2;\n}} {cty};"
                        );
                    }
                    let zero = format!("(({cty}){{0}})");
                    let eq = format!(
                        "({} && {} && {})",
                        tuple_field_eq(ac, "av._0", "bv._0"),
                        tuple_field_eq(bc, "av._1", "bv._1"),
                        tuple_field_eq(cc, "av._2", "bv._2"),
                    );
                    tags.push((tag, cty, zero, eq));
                }
            }
        }
        // Homogeneous 4-tuples (int,int,int,int) etc. — finite grid, no full 4^4 blowup.
        for (a, ac) in bases {
            let tag = format!("tup_{a}_{a}_{a}_{a}");
            let cty = format!("MakoTup_{a}_{a}_{a}_{a}");
            if self.note_tuple_typedef(
                &cty,
                vec![(*ac).into(), (*ac).into(), (*ac).into(), (*ac).into()],
            ) {
                let _ = writeln!(
                    self.out,
                    "typedef struct {{\n    {ac} _0;\n    {ac} _1;\n    {ac} _2;\n    {ac} _3;\n}} {cty};"
                );
            }
            let zero = format!("(({cty}){{0}})");
            let eq = format!(
                "({} && {} && {} && {})",
                tuple_field_eq(ac, "av._0", "bv._0"),
                tuple_field_eq(ac, "av._1", "bv._1"),
                tuple_field_eq(ac, "av._2", "bv._2"),
                tuple_field_eq(ac, "av._3", "bv._3"),
            );
            tags.push((tag, cty, zero, eq));
        }
        // Named struct/enum × scalar 2-tuples (and reverse).
        let mut named: Vec<(String, String)> = self
            .structs
            .iter()
            .map(|(n, s)| (n.clone(), s.c_name.clone()))
            .collect();
        for (n, info) in &self.enums {
            named.push((n.clone(), info.c_name.clone()));
        }
        named.sort_by(|a, b| a.0.cmp(&b.0));
        for (_n, nc) in &named {
            // Tag fragment = C mono name (Point / MakoEnum_Color) to match Expr::Tuple.
            let tn = nc.as_str();
            for (b, bc) in bases {
                // (Named, scalar)
                let tag = format!("tup_{tn}_{b}");
                let cty = format!("MakoTup_{tn}_{b}");
                if self.note_tuple_typedef(&cty, vec![nc.clone(), (*bc).into()]) {
                    let _ = writeln!(
                        self.out,
                        "typedef struct {{\n    {nc} _0;\n    {bc} _1;\n}} {cty};"
                    );
                }
                let zero = format!("(({cty}){{0}})");
                let eq = format!(
                    "({} && {})",
                    tuple_field_eq(nc, "av._0", "bv._0"),
                    tuple_field_eq(bc, "av._1", "bv._1"),
                );
                tags.push((tag, cty, zero, eq));
                // (scalar, Named)
                let tag = format!("tup_{b}_{tn}");
                let cty = format!("MakoTup_{b}_{tn}");
                if self.note_tuple_typedef(&cty, vec![(*bc).into(), nc.clone()]) {
                    let _ = writeln!(
                        self.out,
                        "typedef struct {{\n    {bc} _0;\n    {nc} _1;\n}} {cty};"
                    );
                }
                let zero = format!("(({cty}){{0}})");
                let eq = format!(
                    "({} && {})",
                    tuple_field_eq(bc, "av._0", "bv._0"),
                    tuple_field_eq(nc, "av._1", "bv._1"),
                );
                tags.push((tag, cty, zero, eq));
            }
            // (Named, Named) same type only — common pair shape without N² blowup
            let tag = format!("tup_{tn}_{tn}");
            let cty = format!("MakoTup_{tn}_{tn}");
            if self.note_tuple_typedef(&cty, vec![nc.clone(), nc.clone()]) {
                let _ = writeln!(
                    self.out,
                    "typedef struct {{\n    {nc} _0;\n    {nc} _1;\n}} {cty};"
                );
            }
            let zero = format!("(({cty}){{0}})");
            let eq = format!(
                "({} && {})",
                tuple_field_eq(nc, "av._0", "bv._0"),
                tuple_field_eq(nc, "av._1", "bv._1"),
            );
            tags.push((tag, cty, zero, eq));
        }
        // 2-tuples with one channel handle: (chan[T], scalar) and reverse.
        // Tags match c_type_mono_tag / map_tuple_val_tag (chan_int, chan_string, …).
        let chan_parts: Vec<(String, String)> = self
            .leaf_chan_value_specs()
            .into_iter()
            .map(|(tag, cty)| (tag, cty))
            .collect();
        for (ctag, ccty) in &chan_parts {
            for (b, bc) in bases {
                // (chan, scalar)
                let tag = format!("tup_{ctag}_{b}");
                let cty = format!("MakoTup_{ctag}_{b}");
                if self.note_tuple_typedef(&cty, vec![ccty.clone(), (*bc).into()]) {
                    let _ = writeln!(
                        self.out,
                        "typedef struct {{\n    {ccty} _0;\n    {bc} _1;\n}} {cty};"
                    );
                }
                let zero = format!("(({cty}){{0}})");
                let eq = format!(
                    "({} && {})",
                    tuple_field_eq(ccty, "av._0", "bv._0"),
                    tuple_field_eq(bc, "av._1", "bv._1"),
                );
                tags.push((tag, cty, zero, eq));
                // (scalar, chan)
                let tag = format!("tup_{b}_{ctag}");
                let cty = format!("MakoTup_{b}_{ctag}");
                if self.note_tuple_typedef(&cty, vec![(*bc).into(), ccty.clone()]) {
                    let _ = writeln!(
                        self.out,
                        "typedef struct {{\n    {bc} _0;\n    {ccty} _1;\n}} {cty};"
                    );
                }
                let zero = format!("(({cty}){{0}})");
                let eq = format!(
                    "({} && {})",
                    tuple_field_eq(bc, "av._0", "bv._0"),
                    tuple_field_eq(ccty, "av._1", "bv._1"),
                );
                tags.push((tag, cty, zero, eq));
            }
            // (chan, chan) same mono only — e.g. (chan[int], chan[int])
            let tag = format!("tup_{ctag}_{ctag}");
            let cty = format!("MakoTup_{ctag}_{ctag}");
            if self.note_tuple_typedef(&cty, vec![ccty.clone(), ccty.clone()]) {
                let _ = writeln!(
                    self.out,
                    "typedef struct {{\n    {ccty} _0;\n    {ccty} _1;\n}} {cty};"
                );
            }
            let zero = format!("(({cty}){{0}})");
            let eq = format!(
                "({} && {})",
                tuple_field_eq(ccty, "av._0", "bv._0"),
                tuple_field_eq(ccty, "av._1", "bv._1"),
            );
            tags.push((tag, cty, zero, eq));
        }
        // 2-tuples with Option/Result bag fields × scalars (and same-leaf bag pairs).
        // Tags: tup_opt_int_int, tup_int_res_string, tup_opt_int_opt_int, …
        let bag_leaves: &[(&str, &str)] = &[
            ("opt_int", "MakoOptionInt"),
            ("opt_string", "MakoOptionInt"),
            ("opt_float", "MakoOptionInt"),
            ("opt_bool", "MakoOptionInt"),
            ("res_int", "MakoResultInt"),
            ("res_string", "MakoResultInt"),
            ("res_float", "MakoResultInt"),
            ("res_bool", "MakoResultInt"),
        ];
        for (btag, bcty) in bag_leaves {
            for (s, sc) in bases {
                // (bag, scalar)
                let tag = format!("tup_{btag}_{s}");
                let cty = format!("MakoTup_{btag}_{s}");
                if self.note_tuple_typedef(&cty, vec![(*bcty).into(), (*sc).into()]) {
                    let _ = writeln!(
                        self.out,
                        "typedef struct {{\n    {bcty} _0;\n    {sc} _1;\n}} {cty};"
                    );
                }
                let zero = format!("(({cty}){{0}})");
                let eq = format!(
                    "({} && {})",
                    tuple_field_eq(bcty, "av._0", "bv._0"),
                    tuple_field_eq(sc, "av._1", "bv._1"),
                );
                tags.push((tag, cty, zero, eq));
                // (scalar, bag)
                let tag = format!("tup_{s}_{btag}");
                let cty = format!("MakoTup_{s}_{btag}");
                if self.note_tuple_typedef(&cty, vec![(*sc).into(), (*bcty).into()]) {
                    let _ = writeln!(
                        self.out,
                        "typedef struct {{\n    {sc} _0;\n    {bcty} _1;\n}} {cty};"
                    );
                }
                let zero = format!("(({cty}){{0}})");
                let eq = format!(
                    "({} && {})",
                    tuple_field_eq(sc, "av._0", "bv._0"),
                    tuple_field_eq(bcty, "av._1", "bv._1"),
                );
                tags.push((tag, cty, zero, eq));
            }
            // (bag, bag) same mono only — (Option[int], Option[int]) etc.
            let tag = format!("tup_{btag}_{btag}");
            let cty = format!("MakoTup_{btag}_{btag}");
            if self.note_tuple_typedef(&cty, vec![(*bcty).into(), (*bcty).into()]) {
                let _ = writeln!(
                    self.out,
                    "typedef struct {{\n    {bcty} _0;\n    {bcty} _1;\n}} {cty};"
                );
            }
            let zero = format!("(({cty}){{0}})");
            let eq = format!(
                "({} && {})",
                tuple_field_eq(bcty, "av._0", "bv._0"),
                tuple_field_eq(bcty, "av._1", "bv._1"),
            );
            tags.push((tag, cty, zero, eq));
        }
        // Option[chan[T]] / Result[chan[T]] × scalar int (bounded grid)
        for (ctag, _) in &chan_parts {
            for (pref, bcty) in [("opt", "MakoOptionInt"), ("res", "MakoResultInt")] {
                let btag = format!("{pref}_{ctag}");
                // (bag_chan, int) and reverse
                for (s, sc) in [("int", "int64_t"), ("string", "MakoString")] {
                    let tag = format!("tup_{btag}_{s}");
                    let cty = format!("MakoTup_{btag}_{s}");
                    if self.note_tuple_typedef(&cty, vec![bcty.into(), sc.into()]) {
                        let _ = writeln!(
                            self.out,
                            "typedef struct {{\n    {bcty} _0;\n    {sc} _1;\n}} {cty};"
                        );
                    }
                    let zero = format!("(({cty}){{0}})");
                    let eq = format!(
                        "({} && {})",
                        tuple_field_eq(bcty, "av._0", "bv._0"),
                        tuple_field_eq(sc, "av._1", "bv._1"),
                    );
                    tags.push((tag, cty, zero, eq));
                    let tag = format!("tup_{s}_{btag}");
                    let cty = format!("MakoTup_{s}_{btag}");
                    if self.note_tuple_typedef(&cty, vec![sc.into(), bcty.into()]) {
                        let _ = writeln!(
                            self.out,
                            "typedef struct {{\n    {sc} _0;\n    {bcty} _1;\n}} {cty};"
                        );
                    }
                    let zero = format!("(({cty}){{0}})");
                    let eq = format!(
                        "({} && {})",
                        tuple_field_eq(sc, "av._0", "bv._0"),
                        tuple_field_eq(bcty, "av._1", "bv._1"),
                    );
                    tags.push((tag, cty, zero, eq));
                }
            }
            // (chan, Option[int]) and reverse — common “handle + maybe” shape
            let otag = "opt_int";
            let octy = "MakoOptionInt";
            let ccty = chan_map_val_c_ty(ctag);
            {
                let tag = format!("tup_{ctag}_{otag}");
                let cty = format!("MakoTup_{ctag}_{otag}");
                if self.note_tuple_typedef(&cty, vec![ccty.clone(), octy.into()]) {
                    let _ = writeln!(
                        self.out,
                        "typedef struct {{\n    {ccty} _0;\n    {octy} _1;\n}} {cty};"
                    );
                }
                let zero = format!("(({cty}){{0}})");
                let eq = format!(
                    "({} && {})",
                    tuple_field_eq(&ccty, "av._0", "bv._0"),
                    tuple_field_eq(octy, "av._1", "bv._1"),
                );
                tags.push((tag, cty, zero, eq));
            }
            {
                let tag = format!("tup_{otag}_{ctag}");
                let cty = format!("MakoTup_{otag}_{ctag}");
                if self.note_tuple_typedef(&cty, vec![octy.into(), ccty.clone()]) {
                    let _ = writeln!(
                        self.out,
                        "typedef struct {{\n    {octy} _0;\n    {ccty} _1;\n}} {cty};"
                    );
                }
                let zero = format!("(({cty}){{0}})");
                let eq = format!(
                    "({} && {})",
                    tuple_field_eq(octy, "av._0", "bv._0"),
                    tuple_field_eq(&ccty, "av._1", "bv._1"),
                );
                tags.push((tag, cty, zero, eq));
            }
        }
        // Named struct Option/Result × int (and reverse)
        for (tn, _nc) in &named {
            for (pref, bcty) in [("opt", "MakoOptionInt"), ("res", "MakoResultInt")] {
                let btag = format!("{pref}_{tn}");
                let tag = format!("tup_{btag}_int");
                let cty = format!("MakoTup_{btag}_int");
                if self.note_tuple_typedef(&cty, vec![bcty.into(), "int64_t".into()]) {
                    let _ = writeln!(
                        self.out,
                        "typedef struct {{\n    {bcty} _0;\n    int64_t _1;\n}} {cty};"
                    );
                }
                let zero = format!("(({cty}){{0}})");
                let eq = format!(
                    "({} && {})",
                    tuple_field_eq(bcty, "av._0", "bv._0"),
                    tuple_field_eq("int64_t", "av._1", "bv._1"),
                );
                tags.push((tag, cty, zero, eq));
                let tag = format!("tup_int_{btag}");
                let cty = format!("MakoTup_int_{btag}");
                if self.note_tuple_typedef(&cty, vec!["int64_t".into(), bcty.into()]) {
                    let _ = writeln!(
                        self.out,
                        "typedef struct {{\n    int64_t _0;\n    {bcty} _1;\n}} {cty};"
                    );
                }
                let zero = format!("(({cty}){{0}})");
                let eq = format!(
                    "({} && {})",
                    tuple_field_eq("int64_t", "av._0", "bv._0"),
                    tuple_field_eq(bcty, "av._1", "bv._1"),
                );
                tags.push((tag, cty, zero, eq));
            }
        }
        // 3-tuples with exactly one channel + two scalar slots (all positions).
        // Core scalar chans + named-struct chans (struct chans only pair with int/int to bound grid).
        let mut core_chans: Vec<(String, String)> = vec![
            ("chan_int".into(), "MakoChan*".into()),
            ("chan_string".into(), "MakoChanStr*".into()),
            ("chan_float".into(), "MakoChan*".into()),
            ("chan_bool".into(), "MakoChan*".into()),
        ];
        for (ctag, ccty) in self.leaf_chan_value_specs() {
            if ctag.starts_with("chan_")
                && ctag != "chan_int"
                && ctag != "chan_string"
                && ctag != "chan_float"
                && ctag != "chan_bool"
            {
                core_chans.push((ctag, ccty));
            }
        }
        for (ctag, ccty) in &core_chans {
            let is_struct_chan = !matches!(
                ctag.as_str(),
                "chan_int" | "chan_string" | "chan_float" | "chan_bool"
            );
            let scalar_pairs: Vec<(&str, &str)> = if is_struct_chan {
                vec![("int", "int64_t")]
            } else {
                bases.iter().map(|(a, ac)| (*a, *ac)).collect()
            };
            for (a, ac) in &scalar_pairs {
                for (b, bc) in &scalar_pairs {
                    // (chan, s, s)
                    {
                        let tag = format!("tup_{ctag}_{a}_{b}");
                        let cty = format!("MakoTup_{ctag}_{a}_{b}");
                        if self.note_tuple_typedef(
                            &cty,
                            vec![ccty.clone(), (*ac).into(), (*bc).into()],
                        ) {
                            let _ = writeln!(
                                self.out,
                                "typedef struct {{\n    {ccty} _0;\n    {ac} _1;\n    {bc} _2;\n}} {cty};"
                            );
                        }
                        let zero = format!("(({cty}){{0}})");
                        let eq = format!(
                            "({} && {} && {})",
                            tuple_field_eq(ccty, "av._0", "bv._0"),
                            tuple_field_eq(ac, "av._1", "bv._1"),
                            tuple_field_eq(bc, "av._2", "bv._2"),
                        );
                        tags.push((tag, cty, zero, eq));
                    }
                    // (s, chan, s)
                    {
                        let tag = format!("tup_{a}_{ctag}_{b}");
                        let cty = format!("MakoTup_{a}_{ctag}_{b}");
                        if self.note_tuple_typedef(
                            &cty,
                            vec![(*ac).into(), ccty.clone(), (*bc).into()],
                        ) {
                            let _ = writeln!(
                                self.out,
                                "typedef struct {{\n    {ac} _0;\n    {ccty} _1;\n    {bc} _2;\n}} {cty};"
                            );
                        }
                        let zero = format!("(({cty}){{0}})");
                        let eq = format!(
                            "({} && {} && {})",
                            tuple_field_eq(ac, "av._0", "bv._0"),
                            tuple_field_eq(ccty, "av._1", "bv._1"),
                            tuple_field_eq(bc, "av._2", "bv._2"),
                        );
                        tags.push((tag, cty, zero, eq));
                    }
                    // (s, s, chan)
                    {
                        let tag = format!("tup_{a}_{b}_{ctag}");
                        let cty = format!("MakoTup_{a}_{b}_{ctag}");
                        if self.note_tuple_typedef(
                            &cty,
                            vec![(*ac).into(), (*bc).into(), ccty.clone()],
                        ) {
                            let _ = writeln!(
                                self.out,
                                "typedef struct {{\n    {ac} _0;\n    {bc} _1;\n    {ccty} _2;\n}} {cty};"
                            );
                        }
                        let zero = format!("(({cty}){{0}})");
                        let eq = format!(
                            "({} && {} && {})",
                            tuple_field_eq(ac, "av._0", "bv._0"),
                            tuple_field_eq(bc, "av._1", "bv._1"),
                            tuple_field_eq(ccty, "av._2", "bv._2"),
                        );
                        tags.push((tag, cty, zero, eq));
                    }
                }
            }
        }
        // []tup for maps_values
        for (tag, vc, _, _) in &tags {
            self.emit_nested_arr_helpers(tag, vc);
        }
        let keys: &[(&str, &str)] = &[
            ("i", "int64_t"),
            ("s", "MakoString"),
            ("f", "double"),
            ("b", "bool"),
        ];
        for (ks, kc) in keys {
            for (tag, vc, zero, eqf) in &tags {
                if !self.want_map(ks, tag) {
                    continue;
                }
                self.emit_map_bag_value_helpers(ks, kc, tag, vc, zero, eqf);
            }
        }
        let mut named_keys: Vec<(String, String)> = self
            .structs
            .iter()
            .map(|(n, s)| (n.clone(), s.c_name.clone()))
            .collect();
        for (n, info) in &self.enums {
            named_keys.push((n.clone(), info.c_name.clone()));
        }
        named_keys.sort_by(|a, b| a.0.cmp(&b.0));
        for (kname, kc) in &named_keys {
            if !self.want_named_key(kname) {
                continue;
            }
            for (tag, vc, zero, eqf) in &tags {
                if !self.want_named_map(kname, tag) {
                    continue;
                }
                self.emit_map_named_key_bag_helpers(kname, kc, tag, vc, zero, eqf);
            }
        }
    }

